// Catálogo corregido contra PHB 2024. Fuente de proyecto: archivos .ts aportados por el usuario.
import type { Spell } from './spells'

export const spells4to9: readonly Spell[] = [
  // -- 4th Level Spells (34 spells)

  { id: "4-arcane-eye", name: "Arcane Eye", level: 4, school: "Divination", castingTime: "Action", range: "30 feet", components: "V, S, M (a bit of bat fur)", duration: "Concentration, up to 1 hour", description: "You create an Invisible, invulnerable eye within range that hovers for the duration. You mentally receive visual information from the eye, which can see in every direction. It also has Darkvision with a range of 30 feet.\n\nAs a Bonus Action, you can move the eye up to 30 feet in any direction. A solid barrier blocks the eye's movement, but the eye can pass through an opening as small as 1 inch in diameter.", classes: ["wizard"] },
  { id: "4-aura-of-life", name: "Aura of Life", level: 4, school: "Abjuration", castingTime: "Action", range: "Self", components: "V", duration: "Concentration, up to 10 minutes", description: "An aura radiates from you in a 30-foot Emanation for the duration. While in the aura, you and your allies have Resistance to Necrotic damage, and your Hit Point maximums can't be reduced. If an ally with 0 Hit Points starts its turn in the aura, that ally regains 1 Hit Point.", classes: ["cleric", "paladin"] },
  { id: "4-banishment", name: "Banishment", level: 4, school: "Abjuration", castingTime: "Action", range: "30 feet", components: "V, S, M (a pentacle)", duration: "Concentration, up to 1 minute", description: "One creature that you can see within range must succeed on a Charisma saving throw or be transported to a harmless demiplane for the duration. While there, the target has the Incapacitated condition. When the spell ends, the target reappears in the space it left or in the nearest unoccupied space if that space is occupied.\n\nIf the target is an Aberration, a Celestial, an Elemental, a Fey, or a Fiend, the target doesn't return if the spell lasts for 1 minute. The target is instead transported to a random location on a plane (GM's choice) associated with its creature type.\n\n_Using a Higher-Level Spell Slot._ You can target one additional creature for each spell slot level above 4.", classes: ["cleric", "paladin", "sorcerer", "warlock", "wizard"] },
  { id: "4-black-tentacles", name: "Black Tentacles", level: 4, school: "Conjuration", castingTime: "Action", range: "90 feet", components: "V, S, M (a tentacle)", duration: "Concentration, up to 1 minute", description: "Squirming, ebony tentacles fill a 20-foot square on ground that you can see within range. For the duration, these tentacles turn the ground in that area into Difficult Terrain.\n\nEach creature in that area makes a Strength saving throw. On a failed save, it takes 3d6 Bludgeoning damage, and it has the Restrained condition until the spell ends. A creature also makes that save if it enters the area or ends it turn there. A creature makes that save only once per turn.\n\nA Restrained creature can take an action to make a Strength (Athletics) check against your spell save DC, ending the condition on itself on a success.", classes: ["wizard"] },
  { id: "4-blight", name: "Blight", level: 4, school: "Necromancy", castingTime: "Action", range: "30 feet", components: "V, S", duration: "Instantaneous", description: "A creature that you can see within range makes a Constitution saving throw, taking 8d8 Necrotic damage on a failed save or half as much damage on a successful one. A Plant creature automatically fails the save.\n\nAlternatively, target a nonmagical plant that isn't a creature, such as a tree or shrub. It doesn't make a save; it simply withers and dies.\n\n_Using a Higher-Level Spell Slot._ The damage increases by 1d8 for each spell slot level above 4.", classes: ["druid", "sorcerer", "warlock", "wizard"] },
  { id: "4-charm-monster", name: "Charm Monster", level: 4, school: "Enchantment", castingTime: "Action", range: "30 feet", components: "V, S", duration: "1 hour", description: "One creature you can see within range makes a Wisdom saving throw. It does so with Advantage if you or your allies are fighting it. On a failed save, the target has the Charmed condition until the spell ends or until you or your allies damage it. The Charmed creature is Friendly to you. When the spell ends, the target knows it was Charmed by you.\n\n_Using a Higher-Level Spell Slot._ You can target one additional creature for each spell slot level above 4.", classes: ["bard", "druid", "sorcerer", "warlock", "wizard"] },
  { id: "4-compulsion", name: "Compulsion", level: 4, school: "Enchantment", castingTime: "Action", range: "30 feet", components: "V, S", duration: "Concentration, up to 1 minute", description: "Each creature of your choice that you can see within range must succeed on a Wisdom saving throw or have the Charmed condition until the spell ends.\n\nFor the duration, you can take a Bonus Action to designate a direction that is horizontal to you. Each Charmed target must use as much of its movement as possible to move in that direction on its next turn, taking the safest route. After moving in this way, a target repeats the save, ending the spell on itself on a success.", classes: ["bard"] },
  { id: "4-confusion", name: "Confusion", level: 4, school: "Enchantment", castingTime: "Action", range: "90 feet", components: "V, S, M (three nut shells)", duration: "Concentration, up to 1 minute", description: "Each creature in a 10-foot-radius Sphere centered on a point you choose within range must succeed on a Wisdom saving throw, or that target can't take Bonus Actions or Reactions and must roll 1d10 at the start of each of its turns to determine its behavior for that turn, consulting the table below.\n\n<table>\n  <thead>\n    <tr>\n      <th>1d10</th>\n      <th>Behavior for the Turn</th>\n    </tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td>1</td>\n      <td>The target doesn't take an action, and it uses all its movement to move. Roll 1d4 for the direction: 1, north; 2, east; 3, south; or 4, west.</td>\n    </tr>\n    <tr>\n      <td>2–6</td>\n      <td>The target doesn't move or take actions.</td>\n    </tr>\n    <tr>\n      <td>7–8</td>\n      <td>The target doesn't move, and it takes the Attack action to make one melee attack against a random creature within reach. If none are within reach, the target takes no action.</td>\n    </tr>\n    <tr>\n      <td>9–10</td>\n      <td>The target chooses its behavior.</td>\n    </tr>\n  </tbody>\n</table>\n\nAt the end of each of its turns, an affected target repeats the save, ending the spell on itself on a success.\n\n_Using a Higher-Level Spell Slot._ The Sphere's radius increases by 5 feet for each spell slot level above 4.", classes: ["bard", "druid", "sorcerer", "wizard"] },
  { id: "4-conjure-minor-elementals", name: "Conjure Minor Elementals", level: 4, school: "Conjuration", castingTime: "Action", range: "Self", components: "V, S", duration: "Concentration, up to 10 minutes", description: "You conjure spirits from the Elemental Planes that flit around you in a 15-foot Emanation for the duration. Until the spell ends, any attack you make deals an extra 2d8 damage when you hit a creature in the Emanation. This damage is Acid, Cold, Fire, or Lightning (your choice when you make the attack).\n\nIn addition, the ground in the Emanation is Difficult Terrain for your enemies.\n\n_Using a Higher-Level Spell Slot._ The damage increases by 1d8 for each spell slot level above 4.", classes: ["druid", "wizard"] },
  { id: "4-conjure-woodland-beings", name: "Conjure Woodland Beings", level: 4, school: "Conjuration", castingTime: "Action", range: "Self", components: "V, S", duration: "Concentration, up to 10 minutes", description: "You conjure nature spirits that flit around you in a 10-foot Emanation for the duration. Whenever the Emanation enters the space of a creature you can\nsee and whenever a creature you can see enters the Emanation or ends its turn there, you can force that creature to make a Wisdom saving throw. The creature takes 5d8 Force damage on a failed save or half as much damage on a successful one. A creature makes this save only once per turn.\n\nIn addition, you can take the Disengage action as a Bonus Action for the spell's duration.\n\n_Using a Higher-Level Spell Slot._ The damage increases by 1d8 for each spell slot level above 4.", classes: ["druid", "ranger"] },
  { id: "4-control-water", name: "Control Water", level: 4, school: "Transmutation", castingTime: "Action", range: "300 feet", components: "V, S, M (a mixture of water and dust)", duration: "Concentration, up to 10 minutes", description: "Until the spell ends, you control any water inside an area you choose that is a Cube up to 100 feet on a side, using one of the following effects. As a Magic action on your later turns, you can repeat the same effect or choose a different one.\n\n_Flood._ You cause the water level of all standing water in the area to rise by as much as 20 feet. If you\nchoose an area in a large body of water, you instead create a 20-foot tall wave that travels from one side of the area to the other and then crashes. Any Huge or smaller vehicles in the wave's path are carried with it to the other side. Any Huge or smaller vehicles struck by the wave have a 25 percent chance of capsizing.\n\nThe water level remains elevated until the spell ends or you choose a different effect. If this effect produced a wave, the wave repeats on the start of your next turn while the flood effect lasts.\n\n_Part Water._ You part water in the area and create a trench. The trench extends across the spell's area, and the separated water forms a wall to either side. The trench remains until the spell ends or you choose a different effect. The water then slowly fills in the trench over the course of the next round until the normal water level is restored.\n\n_Redirect Flow._ You cause flowing water in the area to move in a direction you choose, even if the water has to flow over obstacles, up walls, or in other unlikely directions. The water in the area moves as you direct it, but once it moves beyond the spell's area, it resumes its flow based on the terrain. The water continues to move in the direction you chose until the spell ends or you choose a different effect.\n\n_Whirlpool._ You cause a whirlpool to form in the center of the area, which must be at least 50 feet square and 25 feet deep. The whirlpool lasts until you choose a different effect or the spell ends. The whirlpool is 5 feet wide at the base, up to 50 feet wide at the top, and 25 feet tall. Any creature in the water and within 25 feet of the whirlpool is pulled 10 feet toward it. When a creature enters the whirlpool for the first time on a turn or ends its turn there, it makes a Strength saving throw. On a failed save, the creature takes 2d8 Bludgeoning damage. On a successful save, the creature takes half as much damage. A creature can swim away from the whirlpool only if it first takes an action to pull away and succeeds on a Strength (Athletics) check against your spell save DC.", classes: ["cleric", "druid", "wizard"] },
  { id: "4-death-ward", name: "Death Ward", level: 4, school: "Abjuration", castingTime: "Action", range: "Touch", components: "V, S", duration: "8 hours", description: "You touch a creature and grant it a measure of protection from death. The first time the target would drop to 0 Hit Points before the spell ends, the target instead drops to 1 Hit Point, and the spell ends.\n\nIf the spell is still in effect when the target is subjected to an effect that would kill it instantly without dealing damage, that effect is negated against the target, and the spell ends.", classes: ["cleric", "paladin"] },
  { id: "4-dimension-door", name: "Dimension Door", level: 4, school: "Conjuration", castingTime: "Action", range: "500 feet", components: "V", duration: "Instantaneous", description: "You teleport to a location within range. You arrive at exactly the spot desired. It can be a place you can see, one you can visualize, or one you can describe by stating distance and direction, such as \"200 feet straight downward\" or \"300 feet upward to the northwest at a 45-degree angle.\"\n\nYou can also teleport one willing creature. The creature must be within 5 feet of you when you teleport, and it teleports to a space within 5 feet of your destination space.\nIf you, the other creature, or both would arrive in a space occupied by a creature or completely filled by one or more objects, you and any creature traveling with you each take 4d6 Force damage, and the teleportation fails.", classes: ["bard", "sorcerer", "warlock", "wizard"] },
  { id: "4-divination", name: "Divination", level: 4, school: "Divination", castingTime: "Action or Ritual", range: "Self", components: "V, S, M (incense worth 25+ GP, which the spell consumes)", duration: "Instantaneous", description: "This spell puts you in contact with a god or a god's servants. You ask one question about a specific goal, event, or activity to occur within 7 days. The GM offers a truthful reply, which might be a short phrase or cryptic rhyme. The spell doesn't account for circumstances that might change the answer, such as the casting of other spells.\n\nIf you cast the spell more than once before finishing a Long Rest, there is a cumulative 25 percent chance for each casting after the first that you get no answer.", classes: ["cleric", "druid", "wizard"] },
  { id: "4-dominate-beast", name: "Dominate Beast", level: 4, school: "Enchantment", castingTime: "Action", range: "60 feet", components: "V, S", duration: "Concentration, up to 1 minute", description: "One Beast you can see within range must succeed on a Wisdom saving throw or have the Charmed condition for the duration. The target has Advantage on the save if you or your allies are fighting it. Whenever the target takes damage, it repeats the save, ending the spell on itself on a success.\n\nYou have a telepathic link with the Charmed target while the two of you are on the same plane of existence. On your turn, you can use this link to issue commands to the target (no action required), such as \"Attack that creature,\" \"Move over there,\" or \"Fetch that object.\" The target does its best to obey on its turn. If it completes an order and doesn't receive further direction from you, it acts and moves as it likes, focusing on protecting itself.\n\nYou can command the target to take a Reaction but must take your own Reaction to do so.\n\n_Using a Higher-Level Spell Slot._ Your Concentration can last longer with a spell slot of level 5 (up to 10 minutes), 6 (up to 1 hour), or 7+ (up to 8 hours).", classes: ["druid", "ranger", "sorcerer"] },
  { id: "4-fabricate", name: "Fabricate", level: 4, school: "Transmutation", castingTime: "10 minutes", range: "120 feet", components: "V, S", duration: "Instantaneous", description: "You convert raw materials into products of the same material. For example, you can fabricate a wooden bridge from a clump of trees, a rope from a patch of hemp, or clothes from flax or wool.\n\nChoose raw materials that you can see within range. You can fabricate a Large or smaller object (contained within a 10-foot Cube or eight connected 5-foot Cubes) given a sufficient quantity of material. If you're working with metal, stone, or another mineral substance, however, the fabricated object can be no larger than Medium (contained within a 5-foot Cube). The quality of any fabricated objects is based on the quality of the raw materials.\n\nCreatures and magic items can't be created by this spell. You also can't use it to create items that require a high degree of skill—such as weapons and armor—unless you have proficiency with the type of Artisan's Tools used to craft such objects.", classes: ["wizard"] },
  { id: "4-faithful-hound", name: "Faithful Hound", level: 4, school: "Conjuration", castingTime: "Action", range: "30 feet", components: "V, S, M (a silver whistle)", duration: "8 hours", description: "You conjure a phantom watchdog in an unoccupied space that you can see within range. The hound remains for the duration or until the two of you are more than 300 feet apart from each other.\n\nNo one but you can see the hound, and it is intangible and invulnerable. When a Small or larger creature comes within 30 feet of it without first speaking the password that you specify when you cast this spell, the hound starts barking loudly. The hound has Truesight with a range of 30 feet.\n\nAt the start of each of your turns, the hound attempts to bite one enemy within 5 feet of it. That enemy must succeed on a Dexterity saving throw or take 4d8 Force damage.\n\nOn your later turns, you can take a Magic action to move the hound up to 30 feet.", classes: ["wizard"] },
  { id: "4-fire-shield", name: "Fire Shield", level: 4, school: "Evocation", castingTime: "Action", range: "Self", components: "V, S, M (a bit of phosphorus or a firefly)", duration: "10 minutes", description: "Wispy flames wreathe your body for the duration, shedding Bright Light in a 10-foot radius and Dim Light for an additional 10 feet.\n\nThe flames provide you with a warm shield or a chill shield, as you choose. The warm shield grants you Resistance to Cold damage, and the chill shield grants you Resistance to Fire damage.\n\nIn addition, whenever a creature within 5 feet of you hits you with a melee attack roll, the shield erupts with flame. The attacker takes 2d8 Fire damage from a warm shield or 2d8 Cold damage from a chill shield.", classes: ["druid", "sorcerer", "wizard"] },
  { id: "4-freedom-of-movement", name: "Freedom of Movement", level: 4, school: "Abjuration", castingTime: "Action", range: "Touch", components: "V, S, M (a leather strap)", duration: "1 hour", description: "You touch a willing creature. For the duration, the target's movement is unaffected by Difficult Terrain, and spells and other magical effects can neither reduce the target's Speed nor cause the target to have the Paralyzed or Restrained conditions. The target also has a Swim Speed equal to its Speed.\n\nIn addition, the target can spend 5 feet of movement to automatically escape from nonmagical restraints, such as manacles or a creature imposing the Grappled condition on it.\n\n_Using a Higher-Level Spell Slot._ You can target one additional creature for each spell slot level above 4.", classes: ["bard", "cleric", "druid", "ranger"] },
  { id: "4-giant-insect", name: "Giant Insect", level: 4, school: "Conjuration", castingTime: "Action", range: "60 feet", components: "V, S", duration: "Concentration, up to 10 minutes", description: "You summon a giant centipede, spider, or wasp (chosen when you cast the spell). It manifests in an unoccupied space you can see within range and uses the Giant Insect stat block. The form you choose determines certain details in its stat block. The creature disappears when it drops to 0 Hit Points or when the spell ends.\n\nThe creature is an ally to you and your allies. In combat, the creature shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don't issue any, it takes the Dodge action and uses its movement to avoid danger.\n_Using a Higher-Level Spell Slot._ Use the spell slot's level for the spell's level in the stat block.\n\n## Giant Insect\n\n_Large Beast, Unaligned_\n\n**AC** 11 + the spell's level\n**HP** 30 + 10 for each spell level above 4\n**Speed** 40 ft., Climb 40 ft., Fly 40 ft. (Wasp only)\n\n<table>\n  <thead>\n    <tr>\n      <th></th>\n      <th>MOD</th>\n      <th>SAVE</th>\n      <th></th>\n      <th>MOD</th>\n      <th>SAVE</th>\n      <th></th>\n      <th>MOD</th>\n      <th>SAVE</th>\n      <th colspan=\"3\"></th>\n    </tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td>STR</td>\n      <td>17</td>\n      <td>+3</td>\n      <td>+3</td>\n      <td>DEX</td>\n      <td>13</td>\n      <td>+1</td>\n      <td>+1</td>\n      <td>CON</td>\n      <td>15</td>\n      <td>+2</td>\n      <td>+2</td>\n    </tr>\n    <tr>\n      <td>INT</td>\n      <td>4</td>\n      <td>−3</td>\n      <td>−3</td>\n      <td>WIS</td>\n      <td>14</td>\n      <td>+2</td>\n      <td>+2</td>\n      <td>CHA</td>\n      <td>3</td>\n      <td>−4</td>\n      <td>−4</td>\n    </tr>\n  </tbody>\n</table>\n\n**Senses** Darkvision 60 ft.; Passive Perception 12\n**Languages** Understands the languages you know\n**CR** None (XP 0; PB equals your Proficiency Bonus)\n\n#### Traits\n\n_Spider Climb._ The insect can climb difficult surfaces, including along ceilings, without needing to make an ability check.\n\n#### Actions\n\n_Multiattack._ The insect makes a number of attacks equal to half this spell's level (round down).\n\n_Poison Jab. Melee Attack Roll:_ Bonus equals your spell attack modifier, reach 10 ft. _Hit:_ 1d6 + 3 plus the spell's level Piercing damage plus 1d4 Poison damage.\n\n_Web Bolt (Spider Only). Ranged Attack Roll:_ Bonus equals your spell attack modifier, range 60 ft. _Hit:_ 1d10 + 3 plus the spell's level Bludgeoning damage, and the target's Speed is reduced to 0 until the start of the insect's next turn.\n\n#### Bonus Actions\n\n_Venomous Spew (Centipede Only). Constitution Saving Throw:_ Your spell save DC, one creature the insect can see within 10 feet. _Failure:_ The target has the Poisoned condition until the start of the insect's next turn.", classes: ["druid"] },
  { id: "4-greater-invisibility", name: "Greater Invisibility", level: 4, school: "Illusion", castingTime: "Action", range: "Touch", components: "V, S", duration: "Concentration, up to 1 minute", description: "A creature you touch has the Invisible condition until the spell ends.", classes: ["bard", "sorcerer", "wizard"] },
  { id: "4-guardian-of-faith", name: "Guardian of Faith", level: 4, school: "Conjuration", castingTime: "Action", range: "30 feet", components: "V", duration: "8 hours", description: "A Large spectral guardian appears and hovers for the duration in an unoccupied space that you can see within range. The guardian occupies that space and is invulnerable, and it appears in a form appropriate for your deity or pantheon.\n\nAny enemy that moves to a space within 10 feet of the guardian for the first time on a turn or starts its turn there makes a Dexterity saving throw, taking 20 Radiant damage on a failed save or half as much damage on a successful one. The guardian vanishes when it has dealt a total of 60 damage.", classes: ["cleric"] },
  { id: "4-hallucinatory-terrain", name: "Hallucinatory Terrain", level: 4, school: "Illusion", castingTime: "10 minutes", range: "300 feet", components: "V, S, M (a mushroom)", duration: "24 hours", description: "You make natural terrain in a 150-foot Cube in range look, sound, and smell like another sort of natural terrain. Thus, open fields or a road can be made to resemble a swamp, hill, crevasse, or some other difficult or impassable terrain. A pond can be made to seem like a grassy meadow, a precipice like a gentle slope, or a rock-strewn gully like a wide and smooth road. Manufactured structures, equipment, and creatures within the area aren't changed.\n\nThe tactile characteristics of the terrain are unchanged, so creatures entering the area are likely to notice the illusion. If the difference isn't obvious by touch, a creature examining the illusion can take the Study action to make an Intelligence (Investigation) check against your spell save DC to disbelieve it. If a creature discerns that the terrain is illusory, the creature sees a vague image superimposed on the real terrain.", classes: ["bard", "druid", "warlock", "wizard"] },
  { id: "4-ice-storm", name: "Ice Storm", level: 4, school: "Evocation", castingTime: "Action", range: "300 feet", components: "V, S, M (a mitten)", duration: "Instantaneous", description: "Hail falls in a 20-foot-radius, 40-foot-high Cylinder centered on a point within range. Each creature in the Cylinder makes a Dexterity saving throw. A creature takes 2d10 Bludgeoning damage and 4d6 Cold damage on a failed save or half as much damage on a successful one.\n\nHailstones turn ground in the Cylinder into Difficult Terrain until the end of your next turn.\n_Using a Higher-Level Spell Slot._ The Bludgeoning damage increases by 1d10 for each spell slot level above 4.", classes: ["druid", "sorcerer", "wizard"] },
  { id: "4-locate-creature", name: "Locate Creature", level: 4, school: "Divination", castingTime: "Action", range: "Self", components: "V, S, M (fur from a bloodhound)", duration: "Concentration, up to 1 hour", description: "Describe or name a creature that is familiar to you. You sense the direction to the creature's location if that creature is within 1,000 feet of you. If the creature is moving, you know the direction of its movement.\n\nThe spell can locate a specific creature known to you or the nearest creature of a specific kind (such as a human or a unicorn) if you have seen such a creature up close—within 30 feet—at least once. If the creature you described or named is in a different form, such as under the effects of a _Flesh to Stone_ or _Polymorph_ spell, this spell doesn't locate the creature.\n\nThis spell can't locate a creature if any thickness of lead blocks a direct path between you and the creature.", classes: ["bard", "cleric", "druid", "paladin", "ranger", "wizard"] },
  { id: "4-phantasmal-killer", name: "Phantasmal Killer", level: 4, school: "Illusion", castingTime: "Action", range: "120 feet", components: "V, S", duration: "Concentration, up to 1 minute", description: "You tap into the nightmares of a creature you can see within range and create an illusion of its deepest fears, visible only to that creature. The target makes a Wisdom saving throw. On a failed save, the target takes 4d10 Psychic damage and has Disadvantage on ability checks and attack rolls for the duration. On a successful save, the target takes half as much damage, and the spell ends.\n\nFor the duration, the target makes a Wisdom saving throw at the end of each of its turns. On a failed save, it takes the Psychic damage again. On a successful save, the spell ends.\n\n_Using a Higher-Level Spell Slot._ The damage increases by 1d10 for each spell slot level above 4.", classes: ["bard", "wizard"] },
  { id: "4-polymorph", name: "Polymorph", level: 4, school: "Transmutation", castingTime: "Action", range: "60 feet", components: "V, S, M (a caterpillar cocoon)", duration: "Concentration, up to 1 hour", description: "You attempt to transform a creature that you can see within range into a Beast. The target must succeed on a Wisdom saving throw or shape-shift into a Beast form for the duration. That form can be any Beast you choose that has a Challenge Rating equal to or less than the target's (or the target's level if it doesn't have a Challenge Rating). The target's game statistics are replaced by the stat block of the chosen Beast, but the target retains its alignment, personality, creature type, Hit Points, and Hit Point Dice. See the \"Animals\" section of \"Monsters\" for a sample of Beast stat blocks.\n\nThe target gains a number of Temporary Hit Points equal to the Hit Points of the Beast form. These Temporary Hit Points vanish if any remain when the spell ends. The spell ends early on the target if it has no Temporary Hit Points left.\n\nThe target is limited in the actions it can perform by the anatomy of its new form, and it can't speak or cast spells.\nThe target's gear melds into the new form. The creature can't use or otherwise benefit from any of that equipment.", classes: ["bard", "druid", "sorcerer", "wizard"] },
  { id: "4-private-sanctum", name: "Private Sanctum", level: 4, school: "Abjuration", castingTime: "10 minutes", range: "120 feet", components: "V, S, M (a thin sheet of lead)", duration: "24 hours", description: "You make an area within range magically secure. The area is a Cube that can be as small as 5 feet to as large as 100 feet on each side. The spell lasts for the duration.\n\nWhen you cast the spell, you decide what sort of security the spell provides, choosing any of the following properties:\n\n- Sound can't pass through the barrier at the edge of the warded area.\n- The barrier of the warded area appears dark and foggy, preventing vision (including Darkvision) through it.\n- Sensors created by Divination spells can't appear inside the protected area or pass through the barrier at its perimeter.\n- Creatures in the area can't be targeted by Divination spells.\n- Nothing can teleport into or out of the warded area.\n- Planar travel is blocked within the warded area.\n\nCasting this spell on the same spot every day for 365 days makes the spell last until dispelled.\n\n_Using a Higher-Level Spell Slot._ You can increase the size of the Cube by 100 feet for each spell slot level above 4.", classes: ["wizard"] },
  { id: "4-resilient-sphere", name: "Resilient Sphere", level: 4, school: "Abjuration", castingTime: "Action", range: "30 feet", components: "V, S, M (a glass sphere)", duration: "Concentration, up to 1 minute", description: "A shimmering sphere encloses a Large or smaller creature or object within range. An unwilling creature must succeed on a Dexterity saving throw or be enclosed for the duration.\n\nNothing—not physical objects, energy, or other spell effects—can pass through the barrier, in or out, though a creature in the sphere can breathe there. The sphere is immune to all damage, and a creature or object inside can't be damaged by attacks or effects originating from outside, nor can a creature inside the sphere damage anything outside it.\n\nThe sphere is weightless and just large enough to contain the creature or object inside. An enclosed creature can take an action to push against the sphere's walls and thus roll the sphere at up to half the creature's Speed. Similarly, the globe can be picked up and moved by other creatures.\n\nA _Disintegrate_ spell targeting the globe destroys it without harming anything inside.", classes: ["wizard"] },
  { id: "4-secret-chest", name: "Secret Chest", level: 4, school: "Conjuration", castingTime: "Action", range: "Touch", components: "V, S, M (a chest, 3 feet by 2 feet by 2 feet, constructed from rare materials worth 5,000+ GP, and a Tiny replica of the chest made from the same materials worth 50+ GP)", duration: "Until dispelled", description: "You hide a chest and all its contents on the Ethereal Plane. You must touch the chest and the miniature replica that serve as Material components for the spell. The chest can contain up to 12 cubic feet of nonliving material (3 feet by 2 feet by 2 feet).\n\nWhile the chest remains on the Ethereal Plane, you can take a Magic action and touch the replica to recall the chest. It appears in an unoccupied space on the ground within 5 feet of you. You can send the chest back to the Ethereal Plane by taking a Magic action to touch the chest and the replica.\n\nAfter 60 days, there is a cumulative 5 percent chance at the end of each day that the spell ends. The spell also ends if you cast this spell again or if the Tiny replica chest is destroyed. If the spell ends and the larger chest is on the Ethereal Plane, the chest remains there for you or someone else to find.", classes: ["wizard"] },
  { id: "4-stone-shape", name: "Stone Shape", level: 4, school: "Transmutation", castingTime: "Action", range: "Touch", components: "V, S, M (soft clay)", duration: "Instantaneous", description: "You touch a stone object of Medium size or smaller or a section of stone no more than 5 feet in any dimension and form it into any shape you like. For example, you could shape a large rock into a weapon, statue, or coffer, or you could make a small passage through a wall that is 5 feet thick. You could also shape a stone door or its frame to seal the door shut. The object you create can have up to two hinges and a latch, but finer mechanical detail isn't possible.", classes: ["cleric", "druid", "wizard"] },
  { id: "4-stoneskin", name: "Stoneskin", level: 4, school: "Transmutation", castingTime: "Action", range: "Touch", components: "V, S, M (diamond dust worth 100+ GP, which the spell consumes)", duration: "Concentration, up to 1 hour", description: "Until the spell ends, one willing creature you touch has Resistance to Bludgeoning, Piercing, and Slashing damage.", classes: ["druid", "ranger", "sorcerer", "wizard"] },
  { id: "4-vitriolic-sphere", name: "Vitriolic Sphere", level: 4, school: "Evocation", castingTime: "Action", range: "150 feet", components: "V, S, M (a drop of bile)", duration: "Instantaneous", description: "You point at a location within range, and a glowing, 1-foot-diameter ball of acid streaks there and explodes in a 20-foot-radius Sphere. Each creature in that area makes a Dexterity saving throw. On a failed save, a creature takes 10d4 Acid damage and another 5d4 Acid damage at the end of its next turn. On a successful save, a creature takes half the initial damage only.\n\n_Using a Higher-Level Spell Slot._ The initial damage increases by 2d4 for each spell slot level above 4.", classes: ["sorcerer", "wizard"] },
  { id: "4-wall-of-fire", name: "Wall of Fire", level: 4, school: "Evocation", castingTime: "Action", range: "120 feet", components: "V, S, M (a piece of charcoal)", duration: "Concentration, up to 1 minute", description: "You create a wall of fire on a solid surface within range. You can make the wall up to 60 feet long, 20 feet high, and 1 foot thick, or a ringed wall up to 20 feet in diameter, 20 feet high, and 1 foot thick. The wall is opaque and lasts for the duration.\n\nWhen the wall appears, each creature in its area makes a Dexterity saving throw, taking 5d8 Fire damage on a failed save or half as much damage on a successful one.\n\nOne side of the wall, selected by you when you cast this spell, deals 5d8 Fire damage to each creature that ends its turn within 10 feet of that side or inside the wall. A creature takes the same damage when it enters the wall for the first time on a turn or ends its turn there. The other side of the wall deals no damage.\n\n_Using a Higher-Level Spell Slot._ The damage increases by 1d8 for each spell slot level above 4.", classes: ["druid", "sorcerer", "wizard"] },

  // -- 5th Level Spells (38 spells)

  { id: "5-animate-objects", name: "Animate Objects", level: 5, school: "Transmutation", castingTime: "Action", range: "120 feet", components: "V, S", duration: "Concentration, up to 1 minute", description: "Objects animate at your command. Choose a number of nonmagical objects within range that aren't being worn or carried, aren't fixed to a surface, and aren't Gargantuan. The maximum number of objects is equal to your spellcasting ability modifier; for this number, a Medium or smaller target counts as\none object, a Large target counts as two, and a Huge target counts as three.\n\nEach target animates, sprouts legs, and becomes a Construct that uses the **Animated Object** stat block; this creature is under your control until the spell ends or until it is reduced to 0 Hit Points. Each creature you make with this spell is an ally to you and your allies. In combat, it shares your Initiative count and takes its turn immediately after yours.\n\nUntil the spell ends, you can take a Bonus Action to mentally command any creature you made with this spell if the creature is within 500 feet of you (if you control multiple creatures, you can command any of them at the same time, issuing the same command to each one). If you issue no commands, the creature takes the Dodge action and moves only to avoid harm. When the creature drops to 0 Hit Points, it reverts to its object form, and any remaining damage carries over to that form.\n\n_Using a Higher-Level Spell Slot._ The creature's Slam damage increases by 1d4 (Medium or smaller), 1d6 (Large), or 1d12 (Huge) for each spell slot level above 5.\n\n#### Animated Object\n\n_Huge or Smaller Construct, Unaligned_\n\n**AC** 15\n**HP** 10 (Medium or smaller), 20 (Large), 40 (Huge)\n**Speed** 30 ft.\n\n<table>\n  <tbody>\n    <tr>\n      <td>MOD</td>\n      <td>SAVE</td>\n      <td></td>\n      <td>MOD</td>\n      <td>SAVE</td>\n      <td></td>\n      <td>MOD</td>\n      <td>SAVE</td>\n      <td colspan=\"4\"></td>\n    </tr>\n    <tr>\n      <td>STR</td>\n      <td>16</td>\n      <td>+3</td>\n      <td>+3</td>\n      <td>DEX</td>\n      <td>10</td>\n      <td>+0</td>\n      <td>+0</td>\n      <td>CON</td>\n      <td>10</td>\n      <td>+0</td>\n      <td>+0</td>\n    </tr>\n    <tr>\n      <td>INT</td>\n      <td>3</td>\n      <td>−4</td>\n      <td>−4</td>\n      <td>WIS</td>\n      <td>3</td>\n      <td>−4</td>\n      <td>−4</td>\n      <td>CHA</td>\n      <td>1</td>\n      <td>−5</td>\n      <td>−5</td>\n    </tr>\n  </tbody>\n</table>\n\n**Immunities** Poison, Psychic; Charmed, Exhaustion, Frightened, Paralyzed, Poisoned\n**Senses** Blindsight 30 ft.; Passive Perception 6\n**Languages** Understands the languages you know\n**CR** None (XP 0; PB equals your Proficiency Bonus)\n\n#### Actions\n\n_Slam._ _Melee Attack Roll:_ Bonus equals your spell attack modifier, reach 5 ft. _Hit:_ Force damage equal to 1d4 + 3 (Medium or smaller), 2d6 + 3 + your spellcasting ability modifier (Large), or 2d12 + 3 + your spellcasting ability modifier (Huge).", classes: ["bard", "sorcerer", "wizard"] },
  { id: "5-antilife-shell", name: "Antilife Shell", level: 5, school: "Abjuration", castingTime: "Action", range: "Self", components: "V, S", duration: "Concentration, up to 1 hour", description: "An aura extends from you in a 10-foot Emanation for the duration. The aura prevents creatures other than Constructs and Undead from passing or reaching through it. An affected creature can cast spells or make attacks with Ranged or Reach weapons through the barrier.\n\nIf you move so that an affected creature is forced to pass through the barrier, the spell ends.", classes: ["druid"] },
  { id: "5-arcane-hand", name: "Arcane Hand", level: 5, school: "Evocation", castingTime: "Action", range: "120 feet", components: "V, S, M (an eggshell and a glove)", duration: "Concentration, up to 1 minute", description: "You create a Large hand of shimmering magical energy in an unoccupied space that you can see within range. The hand lasts for the duration, and it moves at your command, mimicking the movements of your own hand.\n\nThe hand is an object that has AC 20 and Hit Points equal to your Hit Point maximum. If it drops to 0 Hit Points, the spell ends. The hand doesn't occupy its space.\n\nWhen you cast the spell and as a Bonus Action on your later turns, you can move the hand up to 60 feet and then cause one of the following effects:\n\n**Clenched Fist.** The hand strikes a target within 5 feet of it. Make a melee spell attack. On a hit, the target takes 5d8 Force damage.\n\n**Forceful Hand.** The hand attempts to push a Huge or smaller creature within 5 feet of it. The target must succeed on a Strength saving throw, or the hand pushes the target up to 5 feet plus a number of feet equal to five times your spellcasting ability modifier. The hand moves with the target, remaining within 5 feet of it.\n\n**Grasping Hand.** The hand attempts to grapple a Huge or smaller creature within 5 feet of it. The target must succeed on a Dexterity saving throw, or the target has the Grappled condition, with an escape DC equal to your spell save DC. While the hand grapples the target, you can take a Bonus Action to cause the hand to crush it, dealing Bludgeoning damage to the target equal to 4d6 plus your spellcasting ability modifier.\n\n**Interposing Hand.** The hand grants you Half Cover against attacks and other effects that originate from its space or that pass through it. In addition, its space counts as Difficult Terrain for your enemies.\n\n_Using a Higher-Level Spell Slot._ The damage of the Clenched Fist increases by 2d8 and the damage of the Grasping Hand increases by 2d6 for each spell slot level above 5.", classes: ["sorcerer", "wizard"] },
  { id: "5-awaken", name: "Awaken", level: 5, school: "Transmutation", castingTime: "8 hours", range: "Touch", components: "V, S, M (an agate worth 1,000+ GP, which the spell consumes)", duration: "Instantaneous", description: "You spend the casting time tracing magical pathways within a precious gemstone, and then touch the target. The target must be either a Beast or Plant creature with an Intelligence of 3 or less or a natural plant that isn't a creature. The target gains\nan Intelligence of 10 and the ability to speak one language you know. If the target is a natural plant, it becomes a Plant creature and gains the ability to move its limbs, roots, vines, creepers, and so forth, and it gains senses similar to a human's. The GM chooses statistics appropriate for the awakened Plant, such as the statistics for the **Awakened Shrub** or **Awakened Tree** in \"Monsters.\"\n\nThe awakened target has the Charmed condition for 30 days or until you or your allies deal damage to it. When that condition ends, the awakened creature chooses its attitude toward you.", classes: ["bard", "druid"] },
  { id: "5-cloudkill", name: "Cloudkill", level: 5, school: "Conjuration", castingTime: "Action", range: "120 feet", components: "V, S", duration: "Concentration, up to 10 minutes", description: "You create a 20-foot-radius Sphere of yellow-green fog centered on a point within range. The fog lasts for the duration or until strong wind (such as the one created by _Gust of Wind_) disperses it, ending the spell. Its area is Heavily Obscured.\n\nEach creature in the Sphere makes a Constitution saving throw, taking 5d8 Poison damage on a failed save or half as much damage on a successful one. A creature must also make this save when the Sphere moves into its space and when it enters the Sphere or ends its turn there. A creature makes this save only once per turn.\n\nThe Sphere moves 10 feet away from you at the start of each of your turns.\n\n_Using a Higher-Level Spell Slot._ The damage increases by 1d8 for each spell slot level above 5.", classes: ["sorcerer", "wizard"] },
  { id: "5-commune", name: "Commune", level: 5, school: "Divination", castingTime: "1 minute or Ritual", range: "Self", components: "V, S, M (incense)", duration: "1 minute", description: "You contact a deity or a divine proxy and ask up to three questions that can be answered with yes or no. You must ask your questions before the spell ends. You receive a correct answer for each question.\n\nDivine beings aren't necessarily omniscient, so you might receive \"unclear\" as an answer if a question pertains to information that lies beyond the deity's knowledge. In a case where a one-word answer could be misleading or contrary to the deity's interests, the GM might offer a short phrase as an answer instead.\n\nIf you cast the spell more than once before finishing a Long Rest, there is a cumulative 25 percent chance for each casting after the first that you get no answer.", classes: ["cleric"] },
  { id: "5-commune-with-nature", name: "Commune with Nature", level: 5, school: "Divination", castingTime: "1 minute or Ritual", range: "Self", components: "V, S", duration: "Instantaneous", description: "You commune with nature spirits and gain knowledge of the surrounding area. In the outdoors, the spell gives you knowledge of the area within 3 miles of you. In caves and other natural underground settings, the radius is limited to 300 feet. The spell\ndoesn't function where nature has been replaced by construction, such as in castles and settlements.\n\nChoose three of the following facts; you learn those facts as they pertain to the spell's area:\n\n• Locations of settlements\n• Locations of portals to other planes of existence\n• Location of one Challenge Rating 10+ creature (GM's choice) that is a Celestial, an Elemental, a Fey, a Fiend, or an Undead\n• The most prevalent kind of plant, mineral, or Beast (you choose which to learn)\n• Locations of bodies of water\n\nFor example, you could determine the location of a powerful monster in the area, the locations of bodies of water, and the locations of any towns.", classes: ["druid", "ranger"] },
  { id: "5-cone-of-cold", name: "Cone of Cold", level: 5, school: "Evocation", castingTime: "Action", range: "Self", components: "V, S, M (a small crystal or glass cone)", duration: "Instantaneous", description: "You unleash a blast of cold air. Each creature in a 60-foot Cone originating from you makes a Constitution saving throw, taking 8d8 Cold damage on a failed save or half as much damage on a successful one. A creature killed by this spell becomes a frozen statue until it thaws.\n\n_Using a Higher-Level Spell Slot._ The damage increases by 1d8 for each spell slot level above 5.", classes: ["druid", "sorcerer", "wizard"] },
  { id: "5-conjure-elemental", name: "Conjure Elemental", level: 5, school: "Conjuration", castingTime: "Action", range: "60 feet", components: "V, S", duration: "Concentration, up to 10 minutes", description: "You conjure a Large, intangible spirit from the Elemental Planes that appears in an unoccupied space within range. Choose the spirit's element, which determines its damage type: air (Lightning), earth (Thunder), fire (Fire), or water (Cold). The spirit lasts for the duration.\n\nWhenever a creature you can see enters the spirit's space or starts its turn within 5 feet of the spirit, you can force that creature to make a Dexterity saving throw if the spirit has no creature Restrained. On failed save, the target takes 8d8 damage of the spirit's type, and the target has the Restrained condition until the spell ends. At the start of each of its turns, the Restrained target repeats the save.\n\nOn a failed save, the target takes 4d8 damage of the spirit's type. On a successful save, the target isn't Restrained by the spirit.\n\n_Using a Higher-Level Spell Slot._ The damage increases by 1d8 for each spell slot level above 5.", classes: ["druid", "wizard"] },
  { id: "5-contact-other-plane", name: "Contact Other Plane", level: 5, school: "Divination", castingTime: "1 minute or Ritual", range: "Self", components: "V", duration: "1 minute", description: "You mentally contact a demigod, the spirit of a long-dead sage, or some other knowledgeable entity from another plane. Contacting this otherworldly intelligence can break your mind. When you cast this spell, make a DC 15 Intelligence saving throw. On a successful save, you can ask the entity up to five questions. You must ask your questions before the spell ends. The GM answers each question with one word, such as \"yes,\" \"no,\" \"maybe,\" \"never,\" \"irrelevant,\" or \"unclear\" (if the entity doesn't know the answer to the question). If a one-word answer would be misleading, the GM might instead offer a short phrase as an answer.\n\nOn a failed save, you take 6d6 Psychic damage and have the Incapacitated condition until you finish a Long Rest. A _Greater Restoration_ spell cast on you ends this effect.", classes: ["warlock", "wizard"] },
  { id: "5-contagion", name: "Contagion", level: 5, school: "Necromancy", castingTime: "Action", range: "Touch", components: "V, S", duration: "7 days", description: "Your touch inflicts a magical contagion. The target must succeed on a Constitution saving throw or take 11d8 Necrotic damage and have the Poisoned condition. Also, choose one ability when you cast the spell. While Poisoned, the target has Disadvantage on saving throws made with the chosen ability.\n\nThe target must repeat the saving throw at the end of each of its turns until it gets three successes or failures. If the target succeeds on three of these saves, the spell ends on the target. If the target fails three of the saves, the spell lasts for 7 days on it.\n\nWhenever the Poisoned target receives an effect that would end the Poisoned condition, the target must succeed on a Constitution saving throw, or the Poisoned condition doesn't end on it.", classes: ["cleric", "druid"] },
  { id: "5-creation", name: "Creation", level: 5, school: "Illusion", castingTime: "1 minute", range: "30 feet", components: "V, S, M (a paintbrush)", duration: "Special", description: "You pull wisps of shadow material from the Shadowfell to create an object within range. It is either an object of vegetable matter (soft goods, rope, wood, and the like) or mineral matter (stone, crystal, metal, and the like). The object must be no larger than a 5-foot Cube, and the object must be of a form and material that you have seen.\n\nThe spell's duration depends on the object's material, as shown in the Materials table. If the object is composed of multiple materials, use the shortest duration. Using any object created by this spell as another spell's Material component causes the other spell to fail.\n\n**Materials**\n\n<table>\n  <thead>\n    <tr>\n      <th>Material</th>\n      <th>Duration</th>\n    </tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td>Vegetable matter</td>\n      <td>24 hours</td>\n    </tr>\n    <tr>\n      <td>Stone or crystal</td>\n      <td>12 hours</td>\n    </tr>\n    <tr>\n      <td>Precious metals</td>\n      <td>1 hour</td>\n    </tr>\n    <tr>\n      <td>Gems</td>\n      <td>10 minutes</td>\n    </tr>\n    <tr>\n      <td>Adamantine or mithral</td>\n      <td>1 minute</td>\n    </tr>\n  </tbody>\n</table>\n\n_Using a Higher-Level Spell Slot._ The Cube increases by 5 feet for each spell slot level above 5.", classes: ["sorcerer", "wizard"] },
  { id: "5-dispel-evil-and-good", name: "Dispel Evil and Good", level: 5, school: "Abjuration", castingTime: "Action", range: "Self", components: "V, S, M (powdered silver and iron)", duration: "Concentration, up to 1 minute", description: "For the duration, Celestials, Elementals, Fey, Fiends, and Undead have Disadvantage on attack rolls against you. You can end the spell early by using either of the following special functions.\n\n_Break Enchantment._ As a Magic action, you touch a creature that is possessed by or has the Charmed or Frightened condition from one or more creatures of the types above. The target is no longer possessed, Charmed, or Frightened by such creatures.\n\n_Dismissal._ As a Magic action, you target one creature you can see within 5 feet of you that has one of the creature types above. The target must succeed on a Charisma saving throw or be sent back to its home plane if it isn't there already. If they aren't on their home plane, Undead are sent to the Shadowfell, and Fey are sent to the Feywild.", classes: ["cleric", "paladin"] },
  { id: "5-dominate-person", name: "Dominate Person", level: 5, school: "Enchantment", castingTime: "Action", range: "60 feet", components: "V, S", duration: "Concentration, up to 1 minute", description: "One Humanoid you can see within range must succeed on a Wisdom saving throw or have the Charmed condition for the duration. The target has Advantage on the save if you or your allies are fighting it. Whenever the target takes damage, it repeats the save, ending the spell on itself on a success.\n\nYou have a telepathic link with the Charmed target while the two of you are on the same plane of existence. On your turn, you can use this link to issue commands to the target (no action required), such as \"Attack that creature,\" \"Move over there,\" or \"Fetch that object.\" The target does its best to obey on its turn. If it completes an order and doesn't receive further direction from you, it acts and moves as it likes, focusing on protecting itself.\n\nYou can command the target to take a Reaction but must take your own Reaction to do so.\n\n_Using a Higher-Level Spell Slot._ Your Concentration can last longer with a spell slot of level 6 (up to 10 minutes), 7 (up to 1 hour), or 8+ (up to 8 hours).", classes: ["bard", "sorcerer", "wizard"] },
  { id: "5-dream", name: "Dream", level: 5, school: "Illusion", castingTime: "1 minute", range: "Special", components: "V, S, M (a handful of sand)", duration: "8 hours", description: "You target a creature you know on the same plane of existence. You or a willing creature you touch enters a trance state to act as a dream messenger. While in the trance, the messenger is Incapacitated and has a Speed of 0.\n\nIf the target is asleep, the messenger appears in the target's dreams and can converse with the target as long as it remains asleep, through the spell's duration. The messenger can also shape the dream's environment, creating landscapes, objects, and other images. The messenger can emerge from the trance at any time, ending the spell. The target recalls the dream perfectly upon waking.\n\nIf the target is awake when you cast the spell, the messenger knows it and can either end the trance (and the spell) or wait for the target to sleep, at which point the messenger enters its dreams.\n\nYou can make the messenger terrifying to the target. If you do so, the messenger can deliver a message of no more than ten words, and then the target makes a Wisdom saving throw. On a failed save, the target gains no benefit from its rest, and it takes 3d6 Psychic damage when it wakes up.", classes: ["bard", "warlock", "wizard"] },
  { id: "5-flame-strike", name: "Flame Strike", level: 5, school: "Evocation", castingTime: "Action", range: "60 feet", components: "V, S, M (a pinch of sulfur)", duration: "Instantaneous", description: "A vertical column of brilliant fire roars down from above. Each creature in a 10-foot-radius, 40-foot-high Cylinder centered on a point within range makes a Dexterity saving throw, taking 5d6 Fire damage and 5d6 Radiant damage on a failed save or half as much damage on a successful one.\n\n_Using a Higher-Level Spell Slot._ The Fire damage and the Radiant damage increase by 1d6 for each spell slot level above 5.", classes: ["cleric"] },
  { id: "5-geas", name: "Geas", level: 5, school: "Enchantment", castingTime: "1 minute", range: "60 feet", components: "V", duration: "30 days", description: "You give a verbal command to a creature that you can see within range, ordering it to carry out some service or refrain from an action or a course of activity as you decide. The target must succeed on a Wisdom saving throw or have the Charmed condition for the duration. The target automatically succeeds if it can't understand your command.\n\nWhile Charmed, the creature takes 5d10 Psychic damage if it acts in a manner directly counter to your command. It takes this damage no more than once each day.\n\nYou can issue any command you choose, short of an activity that would result in certain death. Should you issue a suicidal command, the spell ends.\n\nA _Remove Curse_, _Greater Restoration_, or _Wish_ spell ends this spell.\n\n_Using a Higher-Level Spell Slot._ If you use a level 7 or 8 spell slot, the duration is 365 days. If you use a level 9 spell slot, the spell lasts until it is ended by one of the spells mentioned above.", classes: ["bard", "cleric", "druid", "paladin", "wizard"] },
  { id: "5-greater-restoration", name: "Greater Restoration", level: 5, school: "Abjuration", castingTime: "Action", range: "Touch", components: "V, S, M (diamond dust worth 100+ GP, which the spell consumes)", duration: "Instantaneous", description: "You touch a creature and magically remove one of the following effects from it:\n\n- 1 Exhaustion level\n- The Charmed or Petrified condition\n- A curse, including the target's Attunement to a cursed magic item\n- Any reduction to one of the target's ability scores\n- Any reduction to the target's Hit Point maximum", classes: ["bard", "cleric", "druid", "paladin", "ranger"] },
  { id: "5-hallow", name: "Hallow", level: 5, school: "Abjuration", castingTime: "24 hours", range: "Touch", components: "V, S, M (incense worth 1,000+ GP, which the spell consumes)", duration: "Until dispelled", description: "You touch a point and infuse an area around it with holy or unholy power. The area can have a radius up to 60 feet, and the spell fails if the radius includes an area already under the effect of _Hallow_. The affected area has the following effects.\n\n**Hallowed Ward.** Choose any of these creature types: Aberration, Celestial, Elemental, Fey, Fiend, or Undead. Creatures of the chosen types can't willingly enter the area, and any creature that is possessed by or that has the Charmed or Frightened condition from such creatures isn't possessed, Charmed, or Frightened by them while in the area.\n\n**Extra Effect.** You bind an extra effect to the area from the list below:\n\n**Courage.** Creatures of any types you choose can't gain the Frightened condition while in the area.\n\n**Darkness.** Darkness fills the area. Normal light, as well as magical light created by spells of a level lower than this spell, can't illuminate the area.\n**Daylight.** Bright light fills the area. Magical Darkness created by spells of a level lower than this spell can't extinguish the light.\n\n**Peaceful Rest.** Dead bodies interred in the area can't be turned into Undead.\n\n**Extradimensional Interference.** Creatures of any types you choose can't enter or exit the area using teleportation or interplanar travel.\n\n**Fear.** Creatures of any types you choose have the Frightened condition while in the area.\n\n**Resistance.** Creatures of any types you choose have Resistance to one damage type of your choice while in the area.\n\n**Silence.** No sound can emanate from within the area, and no sound can reach into it.\n\n**Tongues.** Creatures of any types you choose can communicate with any other creature in the area even if they don't share a common language.\n\n**Vulnerability.** Creatures of any types you choose have Vulnerability to one damage type of your choice while in the area.", classes: ["cleric"] },
  { id: "5-hold-monster", name: "Hold Monster", level: 5, school: "Enchantment", castingTime: "Action", range: "90 feet", components: "V, S, M (a straight piece of iron)", duration: "Concentration, up to 1 minute", description: "Choose a creature that you can see within range. The target must succeed on a Wisdom saving throw or have the Paralyzed condition for the duration. At the end of each of its turns, the target repeats the save, ending the spell on itself on a success.\n\n_Using a Higher-Level Spell Slot._ You can target one additional creature for each spell slot level above 5.", classes: ["bard", "sorcerer", "warlock", "wizard"] },
  { id: "5-insect-plague", name: "Insect Plague", level: 5, school: "Conjuration", castingTime: "Action", range: "300 feet", components: "V, S, M (a locust)", duration: "Concentration, up to 10 minutes", description: "Swarming locusts fill a 20-foot-radius Sphere centered on a point you choose within range. The Sphere remains for the duration, and its area is Lightly Obscured and Difficult Terrain.\n\nWhen the swarm appears, each creature in it makes a Constitution saving throw, taking 4d10 Piercing damage on a failed save or half as much damage on a successful one. A creature also makes this save when it enters the spell's area for the first time on a turn or ends its turn there. A creature makes this save only once per turn.\n\n_Using a Higher-Level Spell Slot._ The damage increases by 1d10 for each spell slot level above 5.", classes: ["cleric", "druid", "sorcerer"] },
  { id: "5-legend-lore", name: "Legend Lore", level: 5, school: "Divination", castingTime: "10 minutes", range: "Self", components: "V, S, M (incense worth 250+ GP, which the spell consumes, and four ivory strips worth 50+ GP each)", duration: "Instantaneous", description: "Name or describe a famous person, place, or object. The spell brings to your mind a brief summary of the significant lore about that famous thing, as described by the GM.\n\nThe lore might consist of important details, amusing revelations, or even secret lore that has never been widely known. The more information you already know about the thing, the more precise and detailed the information you receive is. That information is accurate but might be couched in figurative language or poetry, as determined by the GM.\n\nIf the famous thing you chose isn't actually famous, you hear sad musical notes played on a trombone, and the spell fails.", classes: ["bard", "cleric", "wizard"] },
  { id: "5-mass-cure-wounds", name: "Mass Cure Wounds", level: 5, school: "Abjuration", castingTime: "Action", range: "60 feet", components: "V, S", duration: "Instantaneous", description: "A wave of healing energy washes out from a point you can see within range. Choose up to six creatures in a 30-foot-radius Sphere centered on that point. Each target regains Hit Points equal to 5d8 plus your spellcasting ability modifier.\n\n_Using a Higher-Level Spell Slot._ The healing increases by 1d8 for each spell slot level above 5.", classes: ["bard", "cleric", "druid"] },
  { id: "5-mislead", name: "Mislead", level: 5, school: "Illusion", castingTime: "Action", range: "Self", components: "S", duration: "Concentration, up to 1 hour", description: "You gain the Invisible condition at the same time that an illusory double of you appears where you are standing. The double lasts for the duration, but the invisibility ends immediately after you make an attack roll, deal damage, or cast a spell.\n\nAs a Magic action, you can move the illusory double up to twice your Speed and make it gesture, speak, and behave in whatever way you choose. It is intangible and invulnerable.\n\nYou can see through its eyes and hear through its ears as if you were located where it is.", classes: ["bard", "warlock", "wizard"] },
  { id: "5-modify-memory", name: "Modify Memory", level: 5, school: "Enchantment", castingTime: "Action", range: "30 feet", components: "V, S", duration: "Concentration, up to 1 minute", description: "You attempt to reshape another creature's memories. One creature that you can see within range makes a Wisdom saving throw. If you are fighting the creature, it has Advantage on the save. On a failed save, the target has the Charmed condition for the duration. While Charmed in this way, the target also has the Incapacitated condition and is unaware of its surroundings, though it can hear you. If it takes any damage or is targeted by another spell, this spell ends, and no memories are modified.\n\nWhile this charm lasts, you can affect the target's memory of an event that it experienced within the last 24 hours and that lasted no more than 10 minutes. You can permanently eliminate all memory of the event, allow the target to recall the event with perfect clarity, change its memory of the event's details, or create a memory of some other event.\n\nYou must speak to the target to describe how its memories are affected, and it must be able to understand your language for the modified memories to take root. Its mind fills in any gaps in the details of your description. If the spell ends before you finish describing the modified memories, the creature's memory isn't altered. Otherwise, the modified memories take hold when the spell ends.\n\nA modified memory doesn't necessarily affect how a creature behaves, particularly if the memory contradicts the creature's natural inclinations, alignment, or beliefs. An illogical modified memory, such as a false memory of how much the creature enjoyed swimming in acid, is dismissed as a bad dream. The GM might deem a modified memory too nonsensical to affect a creature.\n\nA _Remove Curse_ or _Greater Restoration_ spell cast on the target restores the creature's true memory.\n\n_Using a Higher-Level Spell Slot._ You can alter the target's memories of an event that took place up to 7 days ago (level 6 spell slot), 30 days ago (level 7 spell slot), 365 days ago (level 8 spell slot), or any time in the creature's past (level 9 spell slot).", classes: ["bard", "wizard"] },
  { id: "5-passwall", name: "Passwall", level: 5, school: "Transmutation", castingTime: "Action", range: "30 feet", components: "V, S, M (a pinch of sesame seeds)", duration: "1 hour", description: "A passage appears at a point that you can see on a wooden, plaster, or stone surface (such as a wall, ceiling, or floor) within range and lasts for the duration. You choose the opening's dimensions: up to 5 feet wide, 8 feet tall, and 20 feet deep. The passage creates no instability in a structure surrounding it.\n\nWhen the opening disappears, any creatures or objects still in the passage created by the spell are safely ejected to an unoccupied space nearest to the surface on which you cast the spell.", classes: ["wizard"] },
  { id: "5-planar-binding", name: "Planar Binding", level: 5, school: "Abjuration", castingTime: "1 hour", range: "60 feet", components: "V, S, M (a jewel worth 1,000+ GP, which the spell consumes)", duration: "24 hours", description: "You attempt to bind a Celestial, an Elemental, a Fey, or a Fiend to your service. The creature must be within range for the entire casting of the spell. (Typically, the creature is first summoned into the center of the inverted version of the _Magic Circle_ spell to trap it while this spell is cast.) At the completion of the casting, the target must succeed on a Charisma saving throw or be bound to serve you for the duration. If the creature was summoned or created by another spell, that spell's duration is extended to match the duration of this spell.\n\nA bound creature must follow your commands to the best of its ability. You might command the creature to accompany you on an adventure, to guard a location, or to deliver a message. If the creature is Hostile, it strives to twist your commands to achieve its own objectives. If the creature carries out your commands completely before the spell ends, it travels to you to report this fact if you are on the same plane of existence. If you are on a different plane, it returns to the place where you bound it and remains there until the spell ends.\n\n_Using a Higher-Level Spell Slot._ The duration increases with a spell slot of level 6 (10 days), 7 (30 days), 8 (180 days), and 9 (366 days).", classes: ["bard", "cleric", "druid", "warlock", "wizard"] },
  { id: "5-raise-dead", name: "Raise Dead", level: 5, school: "Necromancy", castingTime: "1 hour", range: "Touch", components: "V, S, M (a diamond worth 500+ GP, which the spell consumes)", duration: "Instantaneous", description: "With a touch, you revive a dead creature if it has been dead no longer than 10 days and it wasn't Undead when it died.\n\nThe creature returns to life with 1 Hit Point. This spell also neutralizes any poisons that affected the creature at the time of death.\n\nThis spell closes all mortal wounds, but it doesn't restore missing body parts. If the creature is lacking body parts or organs integral for its survival—its head, for instance—the spell automatically fails.\n\nComing back from the dead is an ordeal. The target takes a −4 penalty to D20 Tests. Every time the target finishes a Long Rest, the penalty is reduced by 1 until it becomes 0.", classes: ["bard", "cleric", "paladin"] },
  { id: "5-reincarnate", name: "Reincarnate", level: 5, school: "Necromancy", castingTime: "1 hour", range: "Touch", components: "V, S, M (rare oils worth 1,000+ GP, which the spell consumes)", duration: "Instantaneous", description: "You touch a dead Humanoid or a piece of one. If the creature has been dead no longer than 10 days, the spell forms a new body for it and calls the soul to enter that body. Roll 1d10 and consult the table below to determine the body's species, or the GM chooses another playable species.\n\n<table>\n  <thead>\n    <tr>\n      <th>1d10</th>\n      <th>Species</th>\n      <th>1d10</th>\n      <th>Species</th>\n    </tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td>1</td>\n      <td>Roll again.</td>\n      <td>6</td>\n      <td>Goliath</td>\n    </tr>\n    <tr>\n      <td>2</td>\n      <td>Dragonborn</td>\n      <td>7</td>\n      <td>Halfling</td>\n    </tr>\n    <tr>\n      <td>3</td>\n      <td>Dwarf</td>\n      <td>8</td>\n      <td>Human</td>\n    </tr>\n    <tr>\n      <td>4</td>\n      <td>Elf</td>\n      <td>9</td>\n      <td>Orc</td>\n    </tr>\n    <tr>\n      <td>5</td>\n      <td>Gnome</td>\n      <td>10</td>\n      <td>Tiefling</td>\n    </tr>\n  </tbody>\n</table>\n\nThe reincarnated creature makes any choices that a species' description offers, and the creature recalls its former life. It retains the capabilities it had in its original form, except it loses the traits of its previous species and gains the traits of its new one.", classes: ["druid"] },
  { id: "5-scrying", name: "Scrying", level: 5, school: "Divination", castingTime: "10 minutes", range: "Self", components: "V, S, M (a focus worth 1,000+ GP, such as a crystal ball, mirror, or water-filled font)", duration: "Concentration, up to 10 minutes", description: "You can see and hear a creature you choose that is on the same plane of existence as you. The target makes a Wisdom saving throw, which is modified (see the tables below) by how well you know the target and the sort of physical connection you have to it. The target doesn't know what it is making the save against, only that it feels uneasy.\n\n<table>\n  <thead>\n    <tr>\n      <th>Your Knowledge of the Target Is …</th>\n      <th>Save Modifier</th>\n    </tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td>Secondhand (heard of the target)</td>\n      <td>+5</td>\n    </tr>\n    <tr>\n      <td>Firsthand (met the target)</td>\n      <td>+0</td>\n    </tr>\n    <tr>\n      <td>Extensive (know the target well)</td>\n      <td>−5</td>\n    </tr>\n  </tbody>\n</table>\n\n<table>\n  <thead>\n    <tr>\n      <th>You Have the Target's …</th>\n      <th>Save Modifier</th>\n    </tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td>Picture or other likeness</td>\n      <td>−2</td>\n    </tr>\n    <tr>\n      <td>Garment or other possession</td>\n      <td>−4</td>\n    </tr>\n    <tr>\n      <td>Body part, lock of hair, or bit of nail</td>\n      <td>−10</td>\n    </tr>\n  </tbody>\n</table>\n\nOn a successful save, the target isn't affected, and you can't use this spell on it again for 24 hours.\n\nOn a failed save, the spell creates an Invisible, intangible sensor within 10 feet of the target. You can see and hear through the sensor as if you were there. The sensor moves with the target, remaining within 10 feet of it for the duration. If something can see the sensor, it appears as a luminous orb about the size of your fist.\n\nInstead of targeting a creature, you can target a location you have seen. When you do so, the sensor appears at that location and doesn't move.", classes: ["bard", "cleric", "druid", "warlock", "wizard"] },
  { id: "5-seeming", name: "Seeming", level: 5, school: "Illusion", castingTime: "Action", range: "30 feet", components: "V, S", duration: "8 hours", description: "You give an illusory appearance to each creature of your choice that you can see within range. An unwilling target can make a Charisma saving throw, and if it succeeds, it is unaffected by this spell.\n\nYou can give the same appearance or different ones to the targets. The spell can change the appearance of the targets' bodies and equipment. You can make each creature seem 1 foot shorter or taller and appear heavier or lighter. A target's new appearance must have the same basic arrangement of limbs as the target, but the extent of the illusion is otherwise up to you. The spell lasts for the duration.\n\nThe changes wrought by this spell fail to hold up to physical inspection. For example, if you use this spell to add a hat to a creature's outfit, objects pass through the hat.\n\nA creature that takes the Study action to examine a target can make an Intelligence (Investigation) check against your spell save DC. If it succeeds, it becomes aware that the target is disguised.", classes: ["bard", "sorcerer", "wizard"] },
  { id: "5-summon-dragon", name: "Summon Dragon", level: 5, school: "Conjuration", castingTime: "Action", range: "60 feet", components: "V, S, M (an object with the image of a dragon engraved on it worth 500+ GP)", duration: "Concentration, up to 1 hour", description: "You call forth a Dragon spirit. It manifests in an unoccupied space that you can see within range and uses the Draconic Spirit stat block. The creature disappears when it drops to 0 Hit Points or when the spell ends.\n\nThe creature is an ally to you and your allies. In combat, the creature shares your Initiative count, but it takes its turn immediately after yours. It obeys your verbal commands (no action required by you). If you don't issue any, it takes the Dodge action and uses its movement to avoid danger.\n\n_Using a Higher-Level Spell Slot._ Use the spell slot's level for the spell's level in the stat block.\n\n## Draconic Spirit\n\n_Large Dragon, Neutral_\n\n**AC** 14 + the spell's level\n**HP** 50 + 10 for each spell level above 5\n**Speed** 30 ft., Fly 60 ft., Swim 30 ft.\n\n<table>\n  <tbody>\n    <tr>\n      <td>MOD</td>\n      <td>SAVE</td>\n      <td></td>\n      <td>MOD</td>\n      <td>SAVE</td>\n      <td></td>\n      <td>MOD</td>\n      <td>SAVE</td>\n      <td colspan=\"4\"></td>\n    </tr>\n    <tr>\n      <td>STR</td>\n      <td>19</td>\n      <td>+4</td>\n      <td>+4</td>\n      <td>DEX</td>\n      <td>14</td>\n      <td>+2</td>\n      <td>+2</td>\n      <td>CON</td>\n      <td>17</td>\n      <td>+3</td>\n      <td>+3</td>\n    </tr>\n    <tr>\n      <td>INT</td>\n      <td>10</td>\n      <td>+0</td>\n      <td>+0</td>\n      <td>WIS</td>\n      <td>14</td>\n      <td>+2</td>\n      <td>+2</td>\n      <td>CHA</td>\n      <td>14</td>\n      <td>+2</td>\n      <td>+2</td>\n    </tr>\n  </tbody>\n</table>\n\n**Resistances** Acid, Cold, Fire, Lightning, Poison\n**Immunities** Charmed, Frightened, Poisoned\n**Senses** Blindsight 30 ft., Darkvision 60 ft.; Passive Perception 12\n**Languages** Draconic, understands the languages you know\n**CR** None (XP 0; PB equals your Proficiency Bonus)\n\n#### Traits\n\n_Shared Resistances._ When you summon the spirit, choose one of its Resistances. You have Resistance to the chosen damage type until the spell ends.\n\n#### Actions\n\n_Multiattack._ The spirit makes a number of Rend attacks equal to half the spell's level (round down), and it uses Breath Weapon.\n\n_Rend. Melee Attack Roll:_ Bonus equals your spell attack modifier, reach 10 feet. _Hit:_ 1d6 + 4 + the spell's level Piercing damage.\n\n_Breath Weapon. Dexterity Saving Throw:_ DC equals your spell save DC, each creature in a 30-foot Cone. _Failure:_ 2d6 damage of a type this spirit has Resistance to (your choice when you cast the spell). _Success:_ Half damage.", classes: ["wizard"] },
  { id: "5-telekinesis", name: "Telekinesis", level: 5, school: "Transmutation", castingTime: "Action", range: "60 feet", components: "V, S", duration: "Concentration, up to 10 minutes", description: "You gain the ability to move or manipulate creatures or objects by thought. When you cast the spell and as a Magic action on your later turns before the spell ends, you can exert your will on one creature or object that you can see within range, causing the appropriate effect below. You can affect the same target round after round or choose a new one at any time. If you switch targets, the prior target is no longer affected by the spell.\n\n_Creature._ You can try to move a Huge or smaller creature. The target must succeed on a Strength saving throw, or you move it up to 30 feet in any direction within the spell's range. Until the end of your next turn, the creature has the Restrained condition, and if you lift it into the air, it is suspended there. It falls at the end of your next turn unless you use this option on it again and it fails the save.\n\n_Object._ You can try to move a Huge or smaller object. If the object isn't being worn or carried, you automatically move it up to 30 feet in any direction within the spell's range. If the object is worn or carried by a creature, that creature must succeed on a Strength saving throw, or you pull the object away and move it up to 30 feet in any direction within the spell's range.\n\nYou can exert fine control on objects with your telekinetic grip, such as manipulating a simple tool, opening a door or a container, stowing or retrieving an item from an open container, or pouring the contents from a vial.", classes: ["sorcerer", "wizard"] },
  { id: "5-telepathic-bond", name: "Telepathic Bond", level: 5, school: "Divination", castingTime: "Action or Ritual", range: "30 feet", components: "V, S, M (two eggs)", duration: "1 hour", description: "You forge a telepathic link among up to eight willing creatures of your choice within range, psychically linking each creature to all the others for the duration. Creatures that can't communicate in any languages aren't affected by this spell.\n\nUntil the spell ends, the targets can communicate telepathically through the bond whether or not they share a language. The communication is possible over any distance, though it can't extend to other planes of existence.", classes: ["bard", "wizard"] },
  { id: "5-teleportation-circle", name: "Teleportation Circle", level: 5, school: "Conjuration", castingTime: "1 minute", range: "10 feet", components: "V, M (rare inks worth 50+ GP, which the spell consumes)", duration: "1 round", description: "As you cast the spell, you draw a 5-foot-radius circle on the ground inscribed with sigils that link your location to a permanent teleportation circle of your choice whose sigil sequence you know and that is on the same plane of existence as you. A shimmering portal opens within the circle you drew and remains open until the end of your next turn. Any creature that enters the portal instantly appears within 5 feet of the destination circle or in the nearest unoccupied space if that space is occupied.\n\nMany major temples, guildhalls, and other important places have permanent teleportation circles. Each circle includes a unique sigil sequence—a string of runes arranged in a particular pattern.\n\nWhen you first gain the ability to cast this spell, you learn the sigil sequences for two destinations on the Material Plane, determined by the GM. You might learn additional sigil sequences during your adventures. You can commit a new sigil sequence to memory after studying it for 1 minute.\n\nYou can create a permanent teleportation circle by casting this spell in the same location every day for 365 days.", classes: ["bard", "sorcerer", "warlock", "wizard"] },
  { id: "5-tree-stride", name: "Tree Stride", level: 5, school: "Conjuration", castingTime: "Action", range: "Self", components: "V, S", duration: "Concentration, up to 1 minute", description: "You gain the ability to enter a tree and move from inside it to inside another tree of the same kind within 500 feet. Both trees must be living and at least the same size as you. You must use 5 feet of movement to enter a tree. You instantly know the location of all other trees of the same kind within 500 feet and, as part of the move used to enter the tree, can either pass into one of those trees or step out of the tree you're in. You appear in a spot of your choice within 5 feet of the destination tree, using another 5 feet of movement. If you have no movement left, you appear within 5 feet of the tree you entered.\n\nYou can use this transportation ability only once on each of your turns. You must end each turn outside a tree.", classes: ["druid", "ranger"] },
  { id: "5-wall-of-force", name: "Wall of Force", level: 5, school: "Evocation", castingTime: "Action", range: "120 feet", components: "V, S, M (a shard of glass)", duration: "Concentration, up to 10 minutes", description: "An Invisible wall of force springs into existence at a point you choose within range. The wall appears in any orientation you choose, as a horizontal or vertical barrier or at an angle. It can be free floating or resting on a solid surface. You can form it into a hemispherical dome or a globe with a radius of up to 10 feet, or you can shape a flat surface made up of ten 10-foot-by-10-foot panels. Each panel must be contiguous with another panel. In any form, the wall is 1/4 inch thick and lasts for the duration. If the wall cuts through a creature's space when it appears, the creature is pushed to one side of the wall (you choose which side).\n\nNothing can physically pass through the wall. It is immune to all damage and can't be dispelled by _Dispel Magic_. A _Disintegrate_ spell destroys the wall instantly, however. The wall also extends into the Ethereal Plane and blocks ethereal travel through the wall.", classes: ["wizard"] },
  { id: "5-wall-of-stone", name: "Wall of Stone", level: 5, school: "Evocation", castingTime: "Action", range: "120 feet", components: "V, S, M (a cube of granite)", duration: "Concentration, up to 10 minutes", description: "A nonmagical wall of solid stone springs into existence at a point you choose within range. The wall is 6 inches thick and is composed of ten 10-foot-by-10-foot panels. Each panel must be contiguous with another panel. Alternatively, you can create 10-foot-by-20-foot panels that are only 3 inches thick.\n\nIf the wall cuts through a creature's space when it appears, the creature is pushed to one side of the wall (you choose which side). If a creature would be surrounded on all sides by the wall (or the wall and another solid surface), that creature can make a Dexterity saving throw. On a success, it can use its Reaction to move up to its Speed so that it is no longer enclosed by the wall.\n\nThe wall can have any shape you desire, though it can't occupy the same space as a creature or object. The wall doesn't need to be vertical or rest on a firm foundation. It must, however, merge with and be solidly supported by existing stone. Thus, you can use this spell to bridge a chasm or create a ramp.\n\nIf you create a span greater than 20 feet in length, you must halve the size of each panel to create supports. You can crudely shape the wall to create battlements and the like.\n\nThe wall is an object made of stone that can be damaged and thus breached. Each panel has AC 15 and 30 Hit Points per inch of thickness, and it has Immunity to Poison and Psychic damage. Reducing a panel to 0 Hit Points destroys it and might cause connected panels to collapse at the GM's discretion.\n\nIf you maintain your Concentration on this spell for its full duration, the wall becomes permanent and can't be dispelled. Otherwise, the wall disappears when the spell ends.", classes: ["druid", "sorcerer", "wizard"] },

  // -- 6th Level Spells (31 spells)

  { id: "6-blade-barrier", name: "Blade Barrier", level: 6, school: "Evocation", castingTime: "Action", range: "90 feet", components: "V, S", duration: "Concentration, up to 10 minutes", description: "You create a wall of whirling blades made of magical energy. The wall appears within range and lasts for the duration. You make a straight wall up to 100 feet long, 20 feet high, and 5 feet thick, or a ringed wall up to 60 feet in diameter, 20 feet high, and 5 feet thick. The wall provides Three-Quarters Cover, and its space is Difficult Terrain.\n\nAny creature in the wall's space makes a Dexterity saving throw, taking 6d10 Force damage on a failed save or half as much damage on a successful one. A creature also makes that save if it enters the wall's space or ends it turn there. A creature makes that save only once per turn.", classes: ["cleric"] },
  { id: "6-chain-lightning", name: "Chain Lightning", level: 6, school: "Evocation", castingTime: "Action", range: "150 feet", components: "V, S, M (three silver pins)", duration: "Instantaneous", description: "You launch a lightning bolt toward a target you can see within range. Three bolts then leap from that target to as many as three other targets of your choice, each of which must be within 30 feet of the first target. A target can be a creature or an object and can be targeted by only one of the bolts.\n\nEach target makes a Dexterity saving throw, taking 10d8 Lightning damage on a failed save or half as much damage on a successful one.\n\n_Using a Higher-Level Spell Slot._ One additional bolt leaps from the first target to another target for each spell slot level above 6.", classes: ["sorcerer", "wizard"] },
  { id: "6-circle-of-death", name: "Circle of Death", level: 6, school: "Necromancy", castingTime: "Action", range: "150 feet", components: "V, S, M (the powder of a crushed black pearl worth 500+ GP)", duration: "Instantaneous", description: "Negative energy ripples out in a 60-foot-radius Sphere from a point you choose within range. Each creature in that area makes a Constitution saving throw, taking 8d8 Necrotic damage on a failed save or half as much damage on a successful one.\n\n_Using a Higher-Level Spell Slot._ The damage increases by 2d8 for each spell slot level above 6.", classes: ["sorcerer", "warlock", "wizard"] },
  { id: "6-conjure-fey", name: "Conjure Fey", level: 6, school: "Conjuration", castingTime: "Action", range: "60 feet", components: "V, S", duration: "Concentration, up to 10 minutes", description: "You conjure a Medium spirit from the Feywild in an unoccupied space you can see within range. The spirit lasts for the duration, and it looks like a Fey creature of your choice. When the spirit appears, you can make one melee spell attack against a creature within 5 feet of it. On a hit, the target takes Psychic damage equal to 3d12 plus your spellcasting ability modifier, and the target has the Frightened condition until the start of your next turn, with both you and the spirit as the source of the fear.\n\nAs a Bonus Action on your later turns, you can teleport the spirit to an unoccupied space you can see within 30 feet of the space it left and make the attack against a creature within 5 feet of it.\n\n_Using a Higher-Level Spell Slot._ The damage increases by 1d12 for each spell slot level above 6.", classes: ["druid"] },
  { id: "6-contingency", name: "Contingency", level: 6, school: "Abjuration", castingTime: "10 minutes", range: "Self", components: "V, S, M (a gem-encrusted statuette of yourself worth 1,500+ GP)", duration: "10 days", description: "Choose a spell of level 5 or lower that you can cast, that has a casting time of an action, and that can target you. You cast that spell—called the contingent spell—as part of casting _Contingency_, expending spell slots for both, but the contingent spell doesn't come into effect. Instead, it takes effect when a certain trigger occurs. You describe that trigger when you cast the two spells. For example, a _Contingency_ cast with _Water Breathing_ might stipulate that _Water Breathing_ comes into effect when you are engulfed in water or a similar liquid.\n\nThe contingent spell takes effect immediately after the trigger occurs for the first time, whether or not you want it to, and then _Contingency_ ends.\n\nThe contingent spell takes effect only on you, even if it can normally target others. You can use only one _Contingency_ spell at a time. If you cast this spell again, the effect of another _Contingency_ spell on you ends. Also, _Contingency_ ends on you if its material component is ever not on your person.", classes: ["wizard"] },
  { id: "6-create-undead", name: "Create Undead", level: 6, school: "Necromancy", castingTime: "1 minute", range: "10 feet", components: "V, S, M (one 150+ GP black onyx stone for each corpse)", duration: "Instantaneous", description: "You can cast this spell only at night. Choose up to three corpses of Medium or Small Humanoids within range. Each one becomes a **Ghoul** under your control (see \"Monsters\" for its stat block).\n\nAs a Bonus Action on each of your turns, you can mentally command any creature you animated with this spell if the creature is within 120 feet of you (if you control multiple creatures, you can command any of them at the same time, issuing the same command to them). You decide what action the creature will take and where it will move on its next turn, or you can issue a general command, such as to guard a particular place. If you issue no commands, the creature takes the Dodge action and moves only to avoid harm. Once given an order, the creature continues to follow the order until its task is complete.\n\nThe creature is under your control for 24 hours, after which it stops obeying any command you've given it. To maintain control of the creature for another 24 hours, you must cast this spell on the creature before the current 24-hour period ends. This use of the spell reasserts your control over up to three creatures you have animated with this spell rather than animating new ones.\n\n_Using a Higher-Level Spell Slot._ If you use a level 7 spell slot, you can animate or reassert control over four **Ghouls**. If you use a level 8 spell slot, you can animate or reassert control over five **Ghouls** or two **Ghasts** or **Wights**. If you use a level 9 spell slot, you can animate or reassert control over six **Ghouls**, three **Ghasts** or **Wights**, or two **Mummies**. See \"Monsters\" for these stat blocks.", classes: ["cleric", "warlock", "wizard"] },
  { id: "6-disintegrate", name: "Disintegrate", level: 6, school: "Transmutation", castingTime: "Action", range: "60 feet", components: "V, S, M (a lodestone and dust)", duration: "Instantaneous", description: "You launch a green ray at a target you can see within range. The target can be a creature, a nonmagical object, or a creation of magical force, such as the wall created by _Wall of Force_.\n\nA creature targeted by this spell makes a Dexterity saving throw. On a failed save, the target takes 10d6 + 40 Force damage. If this damage reduces it to 0 Hit Points, it and everything nonmagical it is wearing and carrying are disintegrated into gray dust. The target can be revived only by a _True Resurrection_ or a _Wish_ spell.\n\nThis spell automatically disintegrates a Large or smaller nonmagical object or a creation of magical force. If such a target is Huge or larger, this spell disintegrates a 10-foot-Cube portion of it.\n\n_Using a Higher-Level Spell Slot._ The damage increases by 3d6 for each spell slot level above 6.", classes: ["sorcerer", "wizard"] },
  { id: "6-eyebite", name: "Eyebite", level: 6, school: "Necromancy", castingTime: "Action", range: "Self", components: "V, S", duration: "Concentration, up to 1 minute", description: "For the duration, your eyes become an inky void. One creature of your choice within 60 feet of you that you can see must succeed on a Wisdom saving throw or be affected by one of the following effects of your choice for the duration.\n\nOn each of your turns until the spell ends, you can take a Magic action to target another creature but can't target a creature again if it has succeeded on a save against this casting of the spell.\n\n_Asleep._ The target has the Unconscious condition. It wakes up if it takes any damage or if another creature takes an action to shake it awake.\n\n_Panicked._ The target has the Frightened condition. On each of its turns, the Frightened target must take the Dash action and move away from you by the safest and shortest route available. If the target moves to a space at least 60 feet away from you where it can't see you, this effect ends.\n\n_Sickened._ The target has the Poisoned condition.", classes: ["bard", "sorcerer", "warlock", "wizard"] },
  { id: "6-find-the-path", name: "Find the Path", level: 6, school: "Divination", castingTime: "1 minute", range: "Self", components: "V, S, M (a set of divination tools—such as cards or runes—worth 100+ GP)", duration: "Concentration, up to 1 day", description: "You magically sense the most direct physical route to a location you name. You must be familiar with the location, and the spell fails if you name a destination on another plane of existence, a moving destination (such as a mobile fortress), or an unspecific destination (such as \"a green dragon's lair\").\n\nFor the duration, as long as you are on the same plane of existence as the destination, you know how far it is and in what direction it lies. Whenever you face a choice of paths along the way there, you know which path is the most direct.", classes: ["bard", "cleric", "druid"] },
  { id: "6-flesh-to-stone", name: "Flesh to Stone", level: 6, school: "Transmutation", castingTime: "Action", range: "60 feet", components: "V, S, M (a cockatrice feather)", duration: "Concentration, up to 1 minute", description: "You attempt to turn one creature that you can see within range into stone. The target makes a Constitution saving throw. On a failed save, it has the Restrained condition for the duration. On a successful save, its Speed is 0 until the start of your next turn. Constructs automatically succeed on the save.\n\nA Restrained target makes another Constitution saving throw at the end of each of its turns. If it successfully saves against this spell three times, the spell ends. If it fails its saves three times, it is turned to stone and has the Petrified condition for the duration. The successes and failures needn't be consecutive; keep track of both until the target collects three of a kind.\n\nIf you maintain your Concentration on this spell for the entire possible duration, the target is Petrified until the condition is ended by _Greater Restoration_ or similar magic.", classes: ["druid", "sorcerer", "wizard"] },
  { id: "6-forbiddance", name: "Forbiddance", level: 6, school: "Abjuration", castingTime: "10 minutes or Ritual", range: "Touch", components: "V, S, M (ruby dust worth 1,000+ GP)", duration: "1 day", description: "You create a ward against magical travel that protects up to 40,000 square feet of floor space to a height of 30 feet above the floor. For the duration, creatures can't teleport into the area or use portals, such as those created by the _Gate_ spell, to enter the area. The spell proofs the area against planar travel, and therefore prevents creatures from accessing the area by way of the Astral Plane, the Ethereal Plane, the Feywild, the Shadowfell, or the _Plane Shift_ spell.\n\nIn addition, the spell damages types of creatures that you choose when you cast it. Choose one or more of the following: Aberrations, Celestials, Elementals, Fey, Fiends, and Undead. When a creature of a chosen type enters the spell's area for the first time on a turn or ends its turn there, the creature takes 5d10 Radiant or Necrotic damage (your choice when you cast this spell).\n\nYou can designate a password when you cast the spell. A creature that speaks the password as it enters the area takes no damage from the spell.\n\nThe spell's area can't overlap with the area of another _Forbiddance_ spell. If you cast _Forbiddance_ every day for 30 days in the same location, the spell lasts until it is dispelled, and the Material components are consumed on the last casting.", classes: ["cleric"] },
  { id: "6-freezing-sphere", name: "Freezing Sphere", level: 6, school: "Evocation", castingTime: "Action", range: "300 feet", components: "V, S, M (a miniature crystal sphere)", duration: "Instantaneous", description: "A frigid globe streaks from you to a point of your choice within range, where it explodes in a 60-foot-radius Sphere. Each creature in that area makes a Constitution saving throw, taking 10d6 Cold damage on failed save or half as much damage on a successful one.\n\nIf the globe strikes a body of water, it freezes the water to a depth of 6 inches over an area 30 feet square. This ice lasts for 1 minute. Creatures that were swimming on the surface of frozen water are trapped in the ice and have the Restrained condition. A trapped creature can take an action to make a Strength (Athletics) check against your spell save DC to break free.\n\nYou can refrain from firing the globe after completing the spell's casting. If you do so, a globe about the size of a sling bullet, cool to the touch, appears in your hand. At any time, you or a creature you give the globe to can throw the globe (to a range of 40 feet) or hurl it with a sling (to the sling's normal range). It shatters on impact, with the same effect as a normal casting of the spell. You can also set the globe down without shattering it. After 1 minute, if the globe hasn't already shattered, it explodes.\n\n_Using a Higher-Level Spell Slot._ The damage increases by 1d6 for each spell slot level above 6.", classes: ["sorcerer", "wizard"] },
  { id: "6-globe-of-invulnerability", name: "Globe of Invulnerability", level: 6, school: "Abjuration", castingTime: "Action", range: "Self", components: "V, S, M (a glass bead)", duration: "Concentration, up to 1 minute", description: "An immobile, shimmering barrier appears in a 10-foot Emanation around you and remains for the duration.\n\nAny spell of level 5 or lower cast from outside the barrier can't affect anything within it. Such a spell can target creatures and objects within the barrier, but the spell has no effect on them. Similarly, the area within the barrier is excluded from areas of effect created by such spells.\n\n_Using a Higher-Level Spell Slot._ The barrier blocks spells of 1 level higher for each spell slot level above 6.", classes: ["sorcerer", "wizard"] },
  { id: "6-guards-and-wards", name: "Guards and Wards", level: 6, school: "Abjuration", castingTime: "1 hour", range: "Touch", components: "V, S, M (a silver rod worth 10+ GP)", duration: "24 hours", description: "You create a ward that protects up to 2,500 square feet of floor space. The warded area can be up to 20 feet tall, and you shape it as one 50-foot square, one hundred 5-foot squares that are contiguous, or twenty-five 10-foot squares that are contiguous.\n\nWhen you cast this spell, you can specify individuals that are unaffected by the spell's effects. You can also specify a password that, when spoken aloud within 5 feet of the warded area, makes the speaker immune to its effects.\nThe spell creates the effects below within the warded area. _Dispel Magic_ has no effect on _Guards and Wards_ itself, but each of the following effects can be dispelled. If all four are dispelled, _Guards and Wards_ ends. If you cast the spell every day for 365 days on the same area, the spell thereafter lasts until all its effects are dispelled.\n\n**Corridors.** Fog fills all the warded corridors, making them Heavily Obscured. In addition, at each intersection or branching passage offering a choice of direction, there is a 50 percent chance that a creature other than you believes it is going in the opposite direction from the one it chooses.\n\n**Doors.** All doors in the warded area are magically locked, as if sealed by the _Arcane Lock_ spell. In addition, you can cover up to ten doors with an illusion to make them appear as plain sections of wall.\n\n**Stairs.** Webs fill all stairs in the warded area from top to bottom, as in the _Web_ spell. These strands regrow in 10 minutes if they are destroyed while _Guards and Wards_ lasts.\n\n**Other Spell Effect.** Place one of the following magical effects within the warded area:\n\n- _Dancing Lights_ in four corridors, with a simple program that the lights repeat as long as _Guards and Wards_ lasts\n- _Magic Mouth_ in two locations\n- _Stinking Cloud_ in two locations (the vapors return within 10 minutes if dispersed while _Guards and Wards_ lasts)\n- _Gust of Wind_ in one corridor or room (the wind blows continuously while the spell lasts)\n- _Suggestion_ in one 5-foot square; any creature that enters that square receives the suggestion mentally", classes: ["bard", "wizard"] },
  { id: "6-harm", name: "Harm", level: 6, school: "Necromancy", castingTime: "Action", range: "60 feet", components: "V, S", duration: "Instantaneous", description: "You unleash virulent magic on a creature you can see within range. The target makes a Constitution saving throw. On a failed save, it takes 14d6 Necrotic damage, and its Hit Point maximum is reduced by an amount equal to the Necrotic damage it took. On a successful save, it takes half as much damage only. This spell can't reduce a target's Hit Point maximum below 1.", classes: ["cleric"] },
  { id: "6-heal", name: "Heal", level: 6, school: "Abjuration", castingTime: "Action", range: "60 feet", components: "V, S", duration: "Instantaneous", description: "Choose a creature that you can see within range. Positive energy washes through the target, restoring 70 Hit Points. This spell also ends the Blinded, Deafened, and Poisoned conditions on the target.\n\n_Using a Higher-Level Spell Slot._ The healing increases by 10 for each spell slot level above 6.", classes: ["cleric", "druid"] },
  { id: "6-heroes-feast", name: "Heroes' Feast", level: 6, school: "Conjuration", castingTime: "10 minutes", range: "Self", components: "V, S, M (a gem-encrusted bowl worth 1,000+ GP, which the spell consumes)", duration: "Instantaneous", description: "You conjure a feast that appears on a surface in an unoccupied 10-foot Cube next to you. The feast takes 1 hour to consume and disappears at the end of that time, and the beneficial effects don't set in until this hour is over. Up to twelve creatures can partake of the feast.\n\nA creature that partakes gains several benefits, which last for 24 hours. The creature has Resistance to Poison damage, and it has Immunity to the Frightened and Poisoned conditions. Its Hit Point maximum also increases by 2d10, and it gains the same number of Hit Points.", classes: ["bard", "cleric", "druid"] },
  { id: "6-instant-summons", name: "Instant Summons", level: 6, school: "Conjuration", castingTime: "1 minute or Ritual", range: "Touch", components: "V, S, M (a sapphire worth 1,000+ GP)", duration: "Until dispelled", description: "You touch the sapphire used in the casting and an object weighing 10 pounds or less whose longest dimension is 6 feet or less. The spell leaves an Invisible mark on that object and invisibly inscribes the object's name on the sapphire. Each time you cast this spell, you must use a different sapphire.\n\nThereafter, you can take a Magic action to speak the object's name and crush the sapphire. The object instantly appears in your hand regardless of physical or planar distances, and the spell ends.\n\nIf another creature is holding or carrying the object, crushing the sapphire doesn't transport it, but instead you learn who that creature is and where that creature is currently located.", classes: ["wizard"] },
  { id: "6-irresistible-dance", name: "Irresistible Dance", level: 6, school: "Enchantment", castingTime: "Action", range: "30 feet", components: "V", duration: "Concentration, up to 1 minute", description: "One creature that you can see within range must make a Wisdom saving throw. On a successful save, the target dances comically until the end of its next turn, during which it must spend all its movement to dance in place.\n\nOn a failed save, the target has the Charmed condition for the duration. While Charmed, the target dances comically, must use all its movement to dance in place, and has Disadvantage on Dexterity saving throws and attack rolls, and other creatures have Advantage on attack rolls against it. On each of its turns, the target can take an action to collect itself and repeat the save, ending the spell on itself on a success.", classes: ["bard", "wizard"] },
  { id: "6-magic-jar", name: "Magic Jar", level: 6, school: "Necromancy", castingTime: "1 minute", range: "Self", components: "V, S, M (a gem, crystal, or reliquary worth 500+ GP)", duration: "Until dispelled", description: "Your body falls into a catatonic state as your soul leaves it and enters the container you used for the spell's Material component. While your soul inhabits the container, you are aware of your surroundings as if you were in the container's space. You can't move or take Reactions. The only action you can take is to project your soul up to 100 feet out of the container, either returning to your living body (and ending the spell) or attempting to possess a Humanoid's body.\n\nYou can attempt to possess any Humanoid within 100 feet of you that you can see (creatures warded by a _Protection from Evil and Good_ or _Magic Circle_ spell can't be possessed). The target makes a Charisma saving throw. On a failed save, your soul enters the target's body, and the target's soul becomes trapped in the container. On a successful save, the target resists your efforts to possess it, and you can't attempt to possess it again for 24 hours.\n\nOnce you possess a creature's body, you control it. Your Hit Points, Hit Point Dice, Strength, Dexterity, Constitution, Speed, and senses are replaced by the creature's. You otherwise keep your game statistics.\n\nMeanwhile, the possessed creature's soul can perceive from the container using its own senses, but it can't move and it is Incapacitated.\n\nWhile possessing a body, you can take a Magic action to return from the host body to the container if it is within 100 feet of you, returning the host creature's soul to its body. If the host body dies while you're in it, the creature dies, and you make a Charisma saving throw against your own spellcasting DC. On a success, you return to the container if it is within 100 feet of you. Otherwise, you die.\n\nIf the container is destroyed or the spell ends, your soul returns to your body. If your body is more than 100 feet away from you or if your body is dead, you die. If another creature's soul is in the container when it is destroyed, the creature's soul returns to its body if the body is alive and within 100 feet. Otherwise, that creature dies.\n\nWhen the spell ends, the container is destroyed.", classes: ["wizard"] },
  { id: "6-mass-suggestion", name: "Mass Suggestion", level: 6, school: "Enchantment", castingTime: "Action", range: "60 feet", components: "V, M (a snake's tongue)", duration: "24 hours", description: "You suggest a course of activity—described in no more than 25 words—to twelve or fewer creatures you can see within range that can hear and understand you. The suggestion must sound achievable and not involve anything that would obviously deal damage to any of the targets or their allies. For example, you could say, \"Walk to the village down that road, and help the villagers there harvest crops until sunset.\" Or you could say, \"Now is not the time for violence. Drop your weapons, and dance! Stop in an hour.\"\n\nEach target must succeed on a Wisdom saving throw or have the Charmed condition for the duration or until you or your allies deal damage to the target. Each Charmed target pursues the suggestion to the best of its ability. The suggested activity can continue for the entire duration, but if the suggested activity can be completed in a shorter time, the spell ends for a target upon completing it.\n\n_Using a Higher-Level Spell Slot._ The duration is longer with a spell slot of level 7 (10 days), 8 (30 days), or 9 (366 days).", classes: ["bard", "sorcerer", "wizard"] },
  { id: "6-move-earth", name: "Move Earth", level: 6, school: "Transmutation", castingTime: "Action", range: "120 feet", components: "V, S, M (a miniature shovel)", duration: "Concentration, up to 2 hours", description: "Choose an area of terrain no larger than 40 feet on a side within range. You can reshape dirt, sand, or clay in the area in any manner you choose for the duration. You can raise or lower the area's elevation, create or fill in a trench, erect or flatten a wall, or form a pillar. The extent of any such changes can't exceed half the area's largest dimension. For example, if you affect a 40-foot square, you can create a pillar up to 20 feet high, raise or lower the square's elevation by up to 20 feet, dig a trench up to 20 feet deep, and so on. It takes 10 minutes for these changes to complete. Because the terrain's transformation occurs slowly, creatures in the area can't usually be trapped or injured by the ground's movement.\n\nAt the end of every 10 minutes you spend concentrating on the spell, you can choose a new area of terrain to affect within range.\n\nThis spell can't manipulate natural stone or stone construction. Rocks and structures shift to accommodate the new terrain. If the way you shape the terrain would make a structure unstable, it might collapse.\n\nSimilarly, this spell doesn't directly affect plant growth. The moved earth carries any plants along with it.", classes: ["druid", "sorcerer", "wizard"] },
  { id: "6-planar-ally", name: "Planar Ally", level: 6, school: "Conjuration", castingTime: "10 minutes", range: "60 feet", components: "V, S", duration: "Instantaneous", description: "You beseech an otherworldly entity for aid. The being must be known to you: a god, a demon prince, or some other being of cosmic power. That entity sends a Celestial, an Elemental, or a Fiend loyal to it to aid you, making the creature appear in an unoccupied space within range. If you know a specific creature's name, you can speak that name when you cast this spell to request that creature, though you might get a different creature anyway (GM's choice).\n\nWhen the creature appears, it is under no compulsion to behave a particular way. You can ask it to perform a service in exchange for payment, but it isn't obliged to do so. The requested task could range from simple (fly us across the chasm, or help us fight a battle) to complex (spy on our enemies, or protect us during our foray into the dungeon). You must be able to communicate with the creature to bargain for its services.\n\nPayment can take a variety of forms. A Celestial might require a sizable donation of gold or magic items to an allied temple, while a Fiend might demand a living sacrifice or a gift of treasure. Some creatures might exchange their service for a quest undertaken by you.\n\nA task that can be measured in minutes requires a payment worth 100 GP per minute. A task measured in hours requires 1,000 GP per hour. And a task measured in days (up to 10 days) requires 10,000 GP per day. The GM can adjust these payments based on the circumstances under which you cast the spell. If the task is aligned with the creature's ethos, the payment might be halved or even waived. Nonhazardous tasks typically require only half the suggested payment, while especially dangerous tasks might require a greater gift. Creatures rarely accept tasks that seem suicidal.\n\nAfter the creature completes the task, or when the agreed-upon duration of service expires, the creature returns to its home plane after reporting back to you if possible. If you are unable to agree on a price for the creature's service, the creature immediately returns to its home plane.", classes: ["cleric"] },
  { id: "6-programmed-illusion", name: "Programmed Illusion", level: 6, school: "Illusion", castingTime: "Action", range: "120 feet", components: "V, S, M (jade dust worth 25+ GP)", duration: "Until dispelled", description: "You create an illusion of an object, a creature, or some other visible phenomenon within range that activates when a specific trigger occurs. The illusion is imperceptible until then. It must be no larger than a 30-foot Cube, and you decide when you cast the spell how the illusion behaves and what sounds it makes. This scripted performance can last up to 5 minutes.\n\nWhen the trigger you specify occurs, the illusion springs into existence and performs in the manner you described. Once the illusion finishes performing, it disappears and remains dormant for 10 minutes, after which the illusion can be activated again.\n\nThe trigger can be as general or as detailed as you like, though it must be based on visual or audible phenomena that occur within 30 feet of the area. For example, you could create an illusion of yourself to appear and warn off others who attempt to open a trapped door.\n\nPhysical interaction with the image reveals it to be illusory, since things can pass through it. A creature that takes the Study action to examine the image can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image, and any noise it makes sounds hollow to the creature.", classes: ["bard", "wizard"] },
  { id: "6-sunbeam", name: "Sunbeam", level: 6, school: "Evocation", castingTime: "Action", range: "Self", components: "V, S, M (a magnifying glass)", duration: "Concentration, up to 1 minute", description: "You launch a sunbeam in a 5-foot-wide, 60-foot-long Line. Each creature in the Line makes a Constitution saving throw. On a failed save, a creature takes 6d8 Radiant damage and has the Blinded condition until the start of your next turn. On a successful save, it takes half as much damage only.\n\nUntil the spell ends, you can take a Magic action to create a new Line of radiance.\n\nFor the duration, a mote of brilliant radiance shines above you. It sheds Bright Light in a 30-foot radius and Dim Light for an additional 30 feet. This light is sunlight.", classes: ["cleric", "druid", "sorcerer", "wizard"] },
  { id: "6-transport-via-plants", name: "Transport via Plants", level: 6, school: "Conjuration", castingTime: "Action", range: "10 feet", components: "V, S", duration: "1 minute", description: "This spell creates a magical link between a Large or larger inanimate plant within range and another plant, at any distance, on the same plane of existence. You must have seen or touched the destination plant at least once before. For the duration, any creature can step into the target plant and exit from the destination plant by using 5 feet of movement.", classes: ["druid"] },
  { id: "6-true-seeing", name: "True Seeing", level: 6, school: "Divination", castingTime: "Action", range: "Touch", components: "V, S, M (mushroom powder worth 25+ GP, which the spell consumes)", duration: "1 hour", description: "For the duration, the willing creature you touch has Truesight with a range of 120 feet.", classes: ["bard", "cleric", "sorcerer", "warlock", "wizard"] },
  { id: "6-wall-of-ice", name: "Wall of Ice", level: 6, school: "Evocation", castingTime: "Action", range: "120 feet", components: "V, S, M (a piece of quartz)", duration: "Concentration, up to 10 minutes", description: "You create a wall of ice on a solid surface within range. You can form it into a hemispherical dome or a globe with a radius of up to 10 feet, or you can shape a flat surface made up of ten 10-foot-square panels. Each panel must be contiguous with another panel. In any form, the wall is 1 foot thick and lasts for the duration.\n\nIf the wall cuts through a creature's space when it appears, the creature is pushed to one side of the wall (you choose which side) and makes a Dexterity saving throw, taking 10d6 Cold damage on a failed save or half as much damage on a successful one.\n\nThe wall is an object that can be damaged and thus breached. It has AC 12 and 30 Hit Points per 10-foot section, and it has Immunity to Cold, Poison, and Psychic damage and Vulnerability to Fire damage. Reducing a 10-foot section of wall to 0 Hit Points destroys it and leaves behind a sheet of frigid air in the space the wall occupied.\n\nA creature moving through the sheet of frigid air for the first time on a turn makes a Constitution saving throw, taking 5d6 Cold damage on a failed save or half as much damage on a successful one.\n_Using a Higher-Level Spell Slot._ The damage the wall deals when it appears increases by 2d6 and the damage from passing through the sheet of frigid air increases by 1d6 for each spell slot level above 6.", classes: ["wizard"] },
  { id: "6-wall-of-thorns", name: "Wall of Thorns", level: 6, school: "Conjuration", castingTime: "Action", range: "120 feet", components: "V, S, M (a handful of thorns)", duration: "Concentration, up to 10 minutes", description: "You create a wall of tangled brush bristling with needle-sharp thorns. The wall appears within range on a solid surface and lasts for the duration. You choose to make the wall up to 60 feet long, 10 feet high, and 5 feet thick or a circle that has a 20-foot diameter and is up to 20 feet high and 5 feet thick. The wall blocks line of sight.\n\nWhen the wall appears, each creature in its area makes a Dexterity saving throw, taking 7d8 Piercing damage on a failed save or half as much damage on a successful one.\n\nA creature can move through the wall, albeit slowly and painfully. For every 1 foot a creature moves through the wall, it must spend 4 feet of movement. Furthermore, the first time a creature enters a space in the wall on a turn or ends its turn there, the creature makes a Dexterity saving throw, taking 7d8 Slashing damage on a failed save or half as much damage on a successful one. A creature makes this save only once per turn.\n\n_Using a Higher-Level Spell Slot._ Both types of damage increase by 1d8 for each spell slot level above 6.", classes: ["druid"] },
  { id: "6-wind-walk", name: "Wind Walk", level: 6, school: "Transmutation", castingTime: "1 minute", range: "30 feet", components: "V, S, M (a candle)", duration: "8 hours", description: "You and up to ten willing creatures of your choice within range assume gaseous forms for the duration, appearing as wisps of cloud. While in this cloud form, a target has a Fly Speed of 300 feet and can hover; it has Immunity to the Prone condition; and it has Resistance to Bludgeoning, Piercing, and Slashing damage. The only actions a target can take in this form are the Dash action or a Magic action to begin reverting to its normal form. Reverting takes 1 minute, during which the target has the Stunned condition. Until the spell ends, the target can revert to cloud form, which also requires a Magic action followed by a 1-minute transformation.\n\nIf a target is in cloud form and flying when the effect ends, the target descends 60 feet per round for 1 minute until it lands, which it does safely. If it can't land after 1 minute, it falls the remaining distance.", classes: ["druid"] },
  { id: "6-word-of-recall", name: "Word of Recall", level: 6, school: "Conjuration", castingTime: "Action", range: "5 feet", components: "V", duration: "Instantaneous", description: "You and up to five willing creatures within 5 feet of you instantly teleport to a previously designated sanctuary. You and any creatures that teleport with you appear in the nearest unoccupied space to the spot you designated when you prepared your sanctuary (see below). If you cast this spell without first preparing a sanctuary, the spell has no effect.\n\nYou must designate a location, such as a temple, as a sanctuary by casting this spell there.", classes: ["cleric"] },

  // -- 7th Level Spells (20 spells)

  { id: "7-arcane-sword", name: "Arcane Sword", level: 7, school: "Evocation", castingTime: "Action", range: "90 feet", components: "V, S, M (a miniature sword worth 250+ GP)", duration: "Concentration, up to 1 minute", description: "You create a spectral sword that hovers within range. It lasts for the duration.\n\nWhen the sword appears, you make a melee spell attack against a target within 5 feet of the sword. On a hit, the target takes Force damage equal to 4d12 plus your spellcasting ability modifier.\n\nOn your later turns, you can take a Bonus Action to move the sword up to 30 feet to a spot you can see and repeat the attack against the same target or a different one.", classes: ["bard", "wizard"] },
  { id: "7-conjure-celestial", name: "Conjure Celestial", level: 7, school: "Conjuration", castingTime: "Action", range: "90 feet", components: "V, S", duration: "Concentration, up to 10 minutes", description: "You conjure a spirit from the Upper Planes, which manifests as a pillar of light in a 10-foot-radius, 40-foot-high Cylinder centered on a point within range. For each creature you can see in the Cylinder, choose which of these lights shines on it:\n\n**Healing Light.** The target regains Hit Points equal to 4d12 plus your spellcasting ability modifier.\n\n**Searing Light.** The target makes a Dexterity saving throw, taking 6d12 Radiant damage on a failed save or half as much damage on a successful one.\n\nUntil the spell ends, Bright Light fills the Cylinder, and when you move on your turn, you can also move the Cylinder up to 30 feet.\n\nWhenever the Cylinder moves into the space of a creature you can see and whenever a creature you can see enters the Cylinder or ends its turn there, you can bathe it in one of the lights. A creature can be affected by this spell only once per turn.\n\n_Using a Higher-Level Spell Slot._ The healing and damage increase by 1d12 for each spell slot level above 7.", classes: ["cleric"] },
  { id: "7-delayed-blast-fireball", name: "Delayed Blast Fireball", level: 7, school: "Evocation", castingTime: "Action", range: "150 feet", components: "V, S, M (a ball of bat guano and sulfur)", duration: "Concentration, up to 1 minute", description: "A beam of yellow light flashes from you, then condenses at a chosen point within range as a glowing bead for the duration. When the spell ends, the bead explodes, and each creature in a 20-foot-radius Sphere centered on that point makes a Dexterity saving throw. A creature takes Fire damage equal to the total accumulated damage on a failed save or half as much damage on a successful one.\n\nThe spell's base damage is 12d6, and the damage increases by 1d6 whenever your turn ends and the spell hasn't ended.\n\nIf a creature touches the glowing bead before the spell ends, that creature makes a Dexterity saving throw. On a failed save, the spell ends, causing the bead to explode. On a successful save, the creature can throw the bead up to 40 feet. If the thrown bead enters a creature's space or collides with a solid object, the spell ends, and the bead explodes.\n\nWhen the bead explodes, flammable objects in the explosion that aren't being worn or carried start burning.\n\n_Using a Higher-Level Spell Slot._ The base damage increases by 1d6 for each spell slot level above 7.", classes: ["sorcerer", "wizard"] },
  { id: "7-divine-word", name: "Divine Word", level: 7, school: "Evocation", castingTime: "Bonus Action", range: "30 feet", components: "V", duration: "Instantaneous", description: "You utter a word imbued with power from the Upper Planes. Each creature of your choice in range makes a Charisma saving throw. On a failed save, a target that has 50 Hit Points or fewer suffers an effect based on its current Hit Points, as shown in the Divine Word Effects table. Regardless of its Hit Points, a Celestial, an Elemental, a Fey, or a Fiend target that fails its save is forced back to its plane of origin (if it isn't there already) and can't return to the current plane for 24 hours by any means short of a _Wish_ spell.\n\n**Divine Word Effects**\n\n<table>\n  <thead>\n    <tr>\n      <th>Hit Points</th>\n      <th>Effect</th>\n    </tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td>0–20</td>\n      <td>The target dies.</td>\n    </tr>\n    <tr>\n      <td>21–30</td>\n      <td>The target has the Blinded, Deafened, and Stunned conditions for 1 hour.</td>\n    </tr>\n    <tr>\n      <td>31–40</td>\n      <td>The target has the Blinded and Deafened conditions for 10 minutes.</td>\n    </tr>\n    <tr>\n      <td>41–50</td>\n      <td>The target has the Deafened condition for 1 minute.</td>\n    </tr>\n  </tbody>\n</table>", classes: ["cleric"] },
  { id: "7-etherealness", name: "Etherealness", level: 7, school: "Conjuration", castingTime: "Action", range: "Self", components: "V, S", duration: "Up to 8 hours", description: "You step into the border regions of the Ethereal Plane, where it overlaps with your current plane. You remain in the Border Ethereal for the duration. During this time, you can move in any direction. If you move up or down, every foot of movement costs an extra foot. You can perceive the plane you left, which looks gray, and you can't see anything there more than 60 feet away.\n\nWhile on the Ethereal Plane, you can affect and be affected only by creatures, objects, and effects on that plane. Creatures that aren't on the Ethereal Plane can't perceive or interact with you unless a feature gives them the ability to do so.\n\nWhen the spell ends, you return to the plane you left in the spot that corresponds to your space in the Border Ethereal. If you appear in an occupied space, you are shunted to the nearest unoccupied space and take Force damage equal to twice the number of feet you are moved.\n\nThis spell ends instantly if you cast it while you are on the Ethereal Plane or a plane that doesn't border it, such as one of the Outer Planes.\n\n_Using a Higher-Level Spell Slot._ You can target up to three willing creatures (including yourself) for each spell slot level above 7. The creatures must be within 10 feet of you when you cast the spell.", classes: ["bard", "cleric", "sorcerer", "warlock", "wizard"] },
  { id: "7-finger-of-death", name: "Finger of Death", level: 7, school: "Necromancy", castingTime: "Action", range: "60 feet", components: "V, S", duration: "Instantaneous", description: "You unleash negative energy toward a creature you can see within range. The target makes a Constitution saving throw, taking 7d8 + 30 Necrotic damage on a failed save or half as much damage on a successful one.\n\nA Humanoid killed by this spell rises at the start of your next turn as a **Zombie** (see \"Monsters\") that follows your verbal orders.", classes: ["sorcerer", "warlock", "wizard"] },
  { id: "7-fire-storm", name: "Fire Storm", level: 7, school: "Evocation", castingTime: "Action", range: "150 feet", components: "V, S", duration: "Instantaneous", description: "A storm of fire appears within range. The area of the storm consists of up to ten 10-foot Cubes, which you arrange as you like. Each Cube must be contiguous with at least one other Cube. Each creature in the area makes a Dexterity saving throw, taking 7d10 Fire damage on a failed save or half as much damage on a successful one.\n\nFlammable objects in the area that aren't being worn or carried start burning.", classes: ["cleric", "druid", "sorcerer"] },
  { id: "7-forcecage", name: "Forcecage", level: 7, school: "Evocation", castingTime: "Action", range: "100 feet", components: "V, S, M (ruby dust worth 1,500+ GP, which the spell consumes)", duration: "Concentration, up to 1 hour", description: "An immobile, Invisible, Cube-shaped prison composed of magical force springs into existence around an area you choose within range. The prison can be a cage or a solid box, as you choose.\n\nA prison in the shape of a cage can be up to 20 feet on a side and is made from 1/2-inch diameter bars spaced 1/2 inch apart. A prison in the shape of a box can be up to 10 feet on a side, creating a solid barrier that prevents any matter from passing through it and blocking any spells cast into or out from the area.\n\nWhen you cast the spell, any creature that is completely inside the cage's area is trapped. Creatures only partially within the area, or those too large to fit inside it, are pushed away from the center of the area until they are completely outside it.\n\nA creature inside the cage can't leave it by nonmagical means. If the creature tries to use teleportation or interplanar travel to leave, it must first make a Charisma saving throw. On a successful save, the creature can use that magic to exit the cage. On a failed save, the creature doesn't exit the cage and wastes the spell or effect. The cage also extends into the Ethereal Plane, blocking ethereal travel.\n\nThis spell can't be dispelled by _Dispel Magic_.", classes: ["bard", "warlock", "wizard"] },
  { id: "7-magnificent-mansion", name: "Magnificent Mansion", level: 7, school: "Conjuration", castingTime: "1 minute", range: "300 feet", components: "V, S, M (a miniature door worth 15+ GP)", duration: "24 hours", description: "You conjure a shimmering door in range that lasts for the duration. The door leads to an extradimensional dwelling and is 5 feet wide and 10 feet tall. You and any creature you designate when you cast the spell can enter the extradimensional dwelling as long as the door remains open. You can open or close it (no action required) if you are within 30 feet of it. While closed, the door is imperceptible.\n\nBeyond the door is a magnificent foyer with numerous chambers beyond. The dwelling's atmosphere is clean, fresh, and warm.\n\nYou can create any floor plan you like for the dwelling, but it can't exceed 50 contiguous 10-foot Cubes. The place is furnished and decorated as you choose. It contains sufficient food to serve a nine-course banquet for up to 100 people. Furnishings and other objects created by this spell dissipate into smoke if removed from it.\n\nA staff of 100 near-transparent servants attends all who enter. You determine the appearance of these servants and their attire. They are invulnerable and obey your commands. Each servant can perform tasks that a human could perform, but they can't attack or take any action that would directly harm another creature. Thus the servants can fetch things, clean, mend, fold clothes, light fires, serve food, pour wine, and so on. The servants can't leave the dwelling.\n\nWhen the spell ends, any creatures or objects left inside the extradimensional space are expelled into the unoccupied spaces nearest to the entrance.", classes: ["bard", "wizard"] },
  { id: "7-mirage-arcane", name: "Mirage Arcane", level: 7, school: "Illusion", castingTime: "10 minutes", range: "Sight", components: "V, S", duration: "10 days", description: "You make terrain in an area up to 1 mile square look, sound, smell, and even feel like some other sort of terrain. Open fields or a road could be made to resemble a swamp, hill, crevasse, or some other rough or impassable terrain. A pond can be made to seem like a grassy meadow, a precipice like a gentle slope, or a rock-strewn gully like a wide and smooth road.\n\nSimilarly, you can alter the appearance of structures or add them where none are present. The spell doesn't disguise, conceal, or add creatures.\n\nThe illusion includes audible, visual, tactile, and olfactory elements, so it can turn clear ground\ninto Difficult Terrain (or vice versa) or otherwise impede movement through the area. Any piece of the illusory terrain (such as a rock or stick) that is removed from the spell's area disappears immediately.\n\nCreatures with Truesight can see through the illusion to the terrain's true form; however, all other elements of the illusion remain, so while the creature is aware of the illusion's presence, the creature can still physically interact with the illusion.", classes: ["bard", "druid", "wizard"] },
  { id: "7-plane-shift", name: "Plane Shift", level: 7, school: "Conjuration", castingTime: "Action", range: "Touch", components: "V, S, M (a forked, metal rod worth 250+ GP and attuned to a plane of existence)", duration: "Instantaneous", description: "You and up to eight willing creatures who link hands in a circle are transported to a different plane of existence. You can specify a target destination in general terms, such as a specific city on the Elemental Plane of Fire or palace on the second level of the Nine Hells, and you appear in or near that destination, as determined by the GM.\n\nAlternatively, if you know the sigil sequence of a teleportation circle on another plane of existence, this spell can take you to that circle. If the teleportation circle is too small to hold all the creatures you transported, they appear in the closest unoccupied spaces next to the circle.", classes: ["cleric", "druid", "sorcerer", "warlock", "wizard"] },
  { id: "7-prismatic-spray", name: "Prismatic Spray", level: 7, school: "Evocation", castingTime: "Action", range: "Self", components: "V, S", duration: "Instantaneous", description: "Eight rays of light flash from you in a 60-foot Cone. Each creature in the Cone makes a Dexterity saving throw. For each target, roll 1d8 to determine which color ray affects it, consulting the Prismatic Rays table.\n\n**Prismatic Rays**\n\n<table>\n  <thead>\n    <tr>\n      <th>1d8</th>\n      <th>Ray</th>\n    </tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td>1</td>\n      <td>**Red.** *Failed Save:* 12d6 Fire damage. *Successful Save:* Half as much damage.</td>\n    </tr>\n    <tr>\n      <td>2</td>\n      <td>**Orange.** *Failed Save:* 12d6 Acid damage. *Successful Save:* Half as much damage.</td>\n    </tr>\n    <tr>\n      <td>3</td>\n      <td>**Yellow.** *Failed Save:* 12d6 Lightning damage. *Successful Save:* Half as much damage.</td>\n    </tr>\n    <tr>\n      <td>4</td>\n      <td>**Green.** *Failed Save:* 12d6 Poison damage. *Successful Save:* Half as much damage.</td>\n    </tr>\n    <tr>\n      <td>5</td>\n      <td>**Blue.** *Failed Save:* 12d6 Cold damage. *Successful Save:* Half as much damage.</td>\n    </tr>\n    <tr>\n      <td>6</td>\n      <td>**Indigo.** *Failed Save:* The target has the Restrained condition and makes a Constitution saving throw at the end of each of its turns. If it successfully saves three times, the condition ends. If it fails three times, it has the Petrified condition until it is freed by an effect like the *Greater Restoration* spell. The successes and failures needn't be consecutive; keep track of both until the target collects three of a kind.</td>\n    </tr>\n    <tr>\n      <td>7</td>\n      <td>**Violet.** *Failed Save:* The target has the Blinded condition and makes a Wisdom saving throw at the start of your next turn. On a successful save, the condition ends. On a failed save, the condition ends, and the creature teleports to another plane of existence (GM's choice).</td>\n    </tr>\n    <tr>\n      <td>8</td>\n      <td>**Special.** The target is struck by two rays. Roll twice, rerolling any 8.</td>\n    </tr>\n  </tbody>\n</table>", classes: ["bard", "sorcerer", "wizard"] },
  { id: "7-project-image", name: "Project Image", level: 7, school: "Illusion", castingTime: "Action", range: "500 miles", components: "V, S, M (a statuette of yourself worth 5+ GP)", duration: "Concentration, up to 1 day", description: "You create an illusory copy of yourself that lasts for the duration. The copy can appear at any location within range that you have seen before, regardless of intervening obstacles. The illusion looks and sounds like you, but it is intangible. If the illusion takes any damage, it disappears, and the spell ends.\n\nYou can see through the illusion's eyes and hear through its ears as if you were in its space. As a Magic action, you can move it up to 60 feet and make it gesture, speak, and behave in whatever way you choose. It mimics your mannerisms perfectly.\n\nPhysical interaction with the image reveals it to be illusory, since things can pass through it. A creature that takes the Study action to examine the image can determine that it is an illusion with a successful Intelligence (Investigation) check against your spell save DC. If a creature discerns the illusion for what it is, the creature can see through the image, and any noise it makes sounds hollow to the creature.", classes: ["bard", "wizard"] },
  { id: "7-regenerate", name: "Regenerate", level: 7, school: "Transmutation", castingTime: "1 minute", range: "Touch", components: "V, S, M (a prayer wheel)", duration: "1 hour", description: "A creature you touch regains 4d8 + 15 Hit Points. For the duration, the target regains 1 Hit Point at the start of each of its turns, and any severed body parts regrow after 2 minutes.", classes: ["bard", "cleric", "druid"] },
  { id: "7-resurrection", name: "Resurrection", level: 7, school: "Necromancy", castingTime: "1 hour", range: "Touch", components: "V, S, M (a diamond worth 1,000+ GP, which the spell consumes)", duration: "Instantaneous", description: "With a touch, you revive a dead creature that has been dead for no more than a century, didn't die of old age, and wasn't Undead when it died.\n\nThe creature returns to life with all its Hit Points. This spell also neutralizes any poisons that affected the creature at the time of death. This spell closes all mortal wounds and restores any missing body parts.\n\nComing back from the dead is an ordeal. The target takes a −4 penalty to D20 Tests. Every time the target finishes a Long Rest, the penalty is reduced by 1 until it becomes 0.\n\nCasting this spell to revive a creature that has been dead for 365 days or longer taxes you. Until you finish a Long Rest, you can't cast spells again, and you have Disadvantage on D20 Tests.", classes: ["bard", "cleric"] },
  { id: "7-reverse-gravity", name: "Reverse Gravity", level: 7, school: "Transmutation", castingTime: "Action", range: "100 feet", components: "V, S, M (a lodestone and iron filings)", duration: "Concentration, up to 1 minute", description: "This spell reverses gravity in a 50-foot-radius, 100-foot high Cylinder centered on a point within range. All creatures and objects in that area that aren't anchored to the ground fall upward and reach the top of the Cylinder. A creature can make a Dexterity saving throw to grab a fixed object it can reach, thus avoiding the fall upward.\n\nIf a ceiling or an anchored object is encountered in this upward fall, creatures and objects strike it just as they would during a downward fall. If an affected creature or object reaches the Cylinder's top without striking anything, it hovers there for the duration. When the spell ends, affected objects and creatures fall downward.", classes: ["druid", "sorcerer", "wizard"] },
  { id: "7-sequester", name: "Sequester", level: 7, school: "Transmutation", castingTime: "Action", range: "Touch", components: "V, S, M (gem dust worth 5,000+ GP, which the spell consumes)", duration: "Until dispelled", description: "With a touch, you magically sequester an object or a willing creature. For the duration, the target has the Invisible condition and can't be targeted by Divination spells, detected by magic, or viewed remotely with magic.\n\nIf the target is a creature, it enters a state of suspended animation; it has the Unconscious condition, doesn't age, and doesn't need food, water, or air.\n\nYou can set a condition for the spell to end early. The condition can be anything you choose, but it must occur or be visible within 1 mile of the target. Examples include \"after 1,000 years\" or \"when the tarrasque awakens.\" This spell also ends if the target takes any damage.", classes: ["wizard"] },
  { id: "7-simulacrum", name: "Simulacrum", level: 7, school: "Illusion", castingTime: "12 hours", range: "Touch", components: "V, S, M (powdered ruby worth 1,500+ GP, which the spell consumes)", duration: "Until dispelled", description: "You create a simulacrum of one Beast or Humanoid that is within 10 feet of you for the entire casting of the spell. You finish the casting by touching both the creature and a pile of ice or snow that is the same size as that creature, and the pile turns into the simulacrum, which is a creature. It uses the game statistics of the original creature at the time of casting, except it is a Construct, its Hit Point maximum is half as much, and it can't cast this spell.\n\nThe simulacrum is Friendly to you and creatures you designate. It obeys your commands and acts on your turn in combat. The simulacrum can't gain levels, and it can't take Short or Long Rests.\n\nIf the simulacrum takes damage, the only way to restore its Hit Points is to repair it as you take a Long Rest, during which you expend components worth 100 GP per Hit Point restored. The simulacrum must stay within 5 feet of you for the repair.\n\nThe simulacrum lasts until it drops to 0 Hit Points, at which point it reverts to snow and melts away. If you cast this spell again, any simulacrum you created with this spell is instantly destroyed.", classes: ["wizard"] },
  { id: "7-symbol", name: "Symbol", level: 7, school: "Abjuration", castingTime: "1 minute", range: "Touch", components: "V, S, M (powdered diamond worth 1,000+ GP, which the spell consumes)", duration: "Until dispelled or triggered", description: "You inscribe a harmful glyph either on a surface (such as a section of floor or wall) or within an object that can be closed (such as a book or chest). The glyph can cover an area no larger than 10 feet in diameter. If you choose an object, it must remain in place; if it is moved more than 10 feet from where you cast this spell, the glyph is broken, and the spell ends without being triggered.\n\nThe glyph is nearly imperceptible and requires a successful Wisdom (Perception) check against your spell save DC to notice.\n\nWhen you inscribe the glyph, you set its trigger and choose which effect the symbol bears: Death, Discord, Fear, Pain, Sleep, or Stunning. Each one is explained below.\n\n_Set the Trigger._ You decide what triggers the glyph when you cast the spell. For glyphs inscribed on a surface, common triggers include touching or stepping on the glyph, removing another object covering it, or approaching within a certain distance of it. For glyphs inscribed within an object, common triggers include opening that object or seeing the glyph.\n\nYou can refine the trigger so that only creatures of certain types activate it (for example, the glyph could be set to affect Aberrations). You can also set conditions for creatures that don't trigger the glyph, such as those who say a certain password.\n\nOnce triggered, the glyph glows, filling a 60-foot-radius Sphere with Dim Light for 10 minutes, after which time the spell ends. Each creature in the Sphere when the glyph activates is targeted by its effect, as is a creature that enters the Sphere for the first time on a turn or ends its turn there. A creature is targeted only once per turn.\n\n_Death._ Each target makes a Constitution saving throw, taking 10d10 Necrotic damage on a failed save or half as much damage on a successful save.\n\n_Discord._ Each target makes a Wisdom saving throw. On a failed save, a target argues with other creatures for 1 minute. During this time, it is incapable of meaningful communication and has Disadvantage on attack rolls and ability checks.\n\n_Fear._ Each target must succeed on a Wisdom saving throw or have the Frightened condition for 1 minute. While Frightened, the target must move at least 30 feet away from the glyph on each of its turns, if able.\n\n_Pain._ Each target must succeed on a Constitution saving throw or have the Incapacitated condition for 1 minute.\n\n_Sleep._ Each target must succeed on a Wisdom saving throw or have the Unconscious condition for 10 minutes. A creature awakens if it takes damage or if someone takes an action to shake it awake.\n\n_Stunning._ Each target must succeed on a Wisdom saving throw or have the Stunned condition for 1 minute.", classes: ["bard", "cleric", "druid", "wizard"] },
  { id: "7-teleport", name: "Teleport", level: 7, school: "Conjuration", castingTime: "Action", range: "10 feet", components: "V", duration: "Instantaneous", description: "This spell instantly transports you and up to eight willing creatures that you can see within range, or a single object that you can see within range, to a destination you select. If you target an object, it must be Large or smaller, and it can't be held or carried by an unwilling creature.\n\nThe destination you choose must be known to you, and it must be on the same plane of existence as you. Your familiarity with the destination determines whether you arrive there successfully. The GM rolls 1d100 and consults the Teleportation Outcome table and the explanations after it.\n\n**Teleportation Outcome**\n\n<table>\n  <thead>\n    <tr>\n      <th>Familiarity</th>\n      <th>Mishap</th>\n      <th>Similar Area</th>\n      <th>Off Target</th>\n      <th>On Target</th>\n    </tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td>Permanent circle</td>\n      <td>—</td>\n      <td>—</td>\n      <td>—</td>\n      <td>01–00</td>\n    </tr>\n    <tr>\n      <td>Linked object</td>\n      <td>—</td>\n      <td>—</td>\n      <td>—</td>\n      <td>01–00</td>\n    </tr>\n    <tr>\n      <td>Very familiar</td>\n      <td>01–05</td>\n      <td>06–13</td>\n      <td>14–24</td>\n      <td>25–00</td>\n    </tr>\n    <tr>\n      <td>Seen casually</td>\n      <td>01–33</td>\n      <td>34–43</td>\n      <td>44–53</td>\n      <td>54–00</td>\n    </tr>\n    <tr>\n      <td>Viewed once or described</td>\n      <td>01–43</td>\n      <td>44–53</td>\n      <td>54–73</td>\n      <td>74–00</td>\n    </tr>\n    <tr>\n      <td>False destination</td>\n      <td>01–50</td>\n      <td>51–00</td>\n      <td>—</td>\n      <td>—</td>\n    </tr>\n  </tbody>\n</table>\n\n_Familiarity._ Here are the meanings of the terms in the table's Familiarity column:\n\n- \"Permanent circle\" means a permanent teleportation circle whose sigil sequence you know.\n- \"Linked object\" means you possess an object taken from the desired destination within the last six months, such as a book from a wizard's library.\n- \"Very familiar\" is a place you have visited often, a place you have carefully studied, or a place you can see when you cast the spell.\n- \"Seen casually\" is a place you have seen more than once but with which you aren't very familiar.\n- \"Viewed once or described\" is a place you have seen once, possibly using magic, or a place you know through someone else's description, perhaps from a map.\n- \"False destination\" is a place that doesn't exist. Perhaps you tried to scry an enemy's sanctum but instead viewed an illusion, or you are attempting to teleport to a location that no longer exists.\n\n_Mishap._ The spell's unpredictable magic results in a difficult journey. Each teleporting creature (or the target object) takes 3d10 Force damage, and the GM rerolls on the table to see where you wind up (multiple mishaps can occur, dealing damage each time).\n\n_Similar Area._ You and your group (or the target object) appear in a different area that's visually or thematically similar to the target area. You appear in the closest similar place. If you are heading for your home laboratory, for example, you might appear in another person's laboratory in the same city.\n\n_Off Target._ You and your group (or the target object) appear 2d12 miles away from the destination in a random direction. Roll 1d8 for the direction: 1, east; 2, southeast; 3, south; 4, southwest; 5, west; 6, northwest; 7, north; or 8, northeast.\n\n_On Target._ You and your group (or the target object) appear where you intended.", classes: ["bard", "sorcerer", "wizard"] },

  // -- 8th Level Spells (17 spells)

  { id: "8-animal-shapes", name: "Animal Shapes", level: 8, school: "Transmutation", castingTime: "Action", range: "30 feet", components: "V, S", duration: "24 hours", description: "Choose any number of willing creatures that you can see within range. Each target shape-shifts into a Large or smaller Beast of your choice that has a Challenge Rating of 4 or lower. You can choose a different form for each target. On later turns, you can take a Magic action to transform the targets again.\n\nA target's game statistics are replaced by the chosen Beast's statistics, but the target retains its creature type; Hit Points; Hit Point Dice; alignment; ability to communicate; and Intelligence, Wisdom, and Charisma scores. The target's actions are limited by the Beast form's anatomy, and it can't cast spells. The target's equipment melds into the new form, and the target can't use any of that equipment while in that form.\n\nThe target gains a number of Temporary Hit Points equal to the Hit Points of the first form into which it shape-shifts. These Temporary Hit Points vanish if any remain when the spell ends. The transformation lasts for the duration or until the target ends it as a Bonus Action.", classes: ["druid"] },
  { id: "8-antimagic-field", name: "Antimagic Field", level: 8, school: "Abjuration", castingTime: "Action", range: "Self", components: "V, S, M (iron filings)", duration: "Concentration, up to 1 hour", description: "An aura of antimagic surrounds you in 10-foot Emanation. No one can cast spells, take Magic actions, or create other magical effects inside the aura, and those things can't target or otherwise affect anything inside it. Magical properties of magic items don't work inside the aura or on anything inside it.\n\nAreas of effect created by spells or other magic can't extend into the aura, and no one can teleport into or out of it or use planar travel there. Portals close temporarily while in the aura.\n\nOngoing spells, except those cast by an Artifact or a deity, are suppressed in the area. While an effect is suppressed, it doesn't function, but the time it spends suppressed counts against its duration.\n\n_Dispel Magic_ has no effect on the aura, and the auras created by different _Antimagic Field_ spells don't nullify each other.", classes: ["cleric", "wizard"] },
  { id: "8-antipathy-sympathy", name: "Antipathy/Sympathy", level: 8, school: "Enchantment", castingTime: "1 hour", range: "60 feet", components: "V, S, M (a mix of vinegar and honey)", duration: "10 days", description: "As you cast the spell, choose whether it creates antipathy or sympathy, and target one creature or object that is Huge or smaller. Then specify a kind of creature, such as red dragons, goblins, or vampires. A creature of the chosen kind makes a Wisdom saving throw when it comes within 120 feet of the target. Your choice of antipathy or sympathy determines what happens to a creature when it fails that save:\n\n**Antipathy.** The creature has the Frightened condition. The Frightened creature must use its movement on its turns to get as far away as possible from the target, moving by the safest route.\n\n**Sympathy.** The creature has the Charmed condition. The Charmed creature must use its movement on its turns to get as close as possible to the target, moving by the safest route. If the creature is within 5 feet of the target, the creature can't willingly move away. If the target damages the Charmed creature, that creature can make a\nWisdom saving throw to end the effect, as described below.\n\n_Ending the Effect._ If the Frightened or Charmed creature ends its turn more than 120 feet away from the target, the creature makes a Wisdom saving throw. On a successful save, the creature is no longer affected by the target. A creature that successfully saves against this effect is immune to it for 1 minute, after which it can be affected again.", classes: ["bard", "druid", "wizard"] },
  { id: "8-befuddlement", name: "Befuddlement", level: 8, school: "Enchantment", castingTime: "Action", range: "150 feet", components: "V, S, M (a key ring with no keys)", duration: "Instantaneous", description: "You blast the mind of a creature that you can see within range. The target makes an Intelligence saving throw.\n\nOn a failed save, the target takes 10d12 Psychic damage and can't cast spells or take the Magic action. At the end of every 30 days, the target repeats the save, ending the effect on a success. The effect can also be ended by the _Greater Restoration_, _Heal_, or _Wish_ spell.\n\nOn a successful save, the target takes half as much damage only.", classes: ["bard", "druid", "warlock", "wizard"] },
  { id: "8-clone", name: "Clone", level: 8, school: "Necromancy", castingTime: "1 hour", range: "Touch", components: "V, S, M (a diamond worth 1,000+ GP, which the spell consumes, and a sealable vessel worth 2,000+ GP that is large enough to hold the creature being cloned)", duration: "Instantaneous", description: "You touch a creature or at least 1 cubic inch of its flesh. An inert duplicate of that creature forms inside the vessel used in the spell's casting and finishes growing after 120 days; you choose whether the finished clone is the same age as the creature or younger. The clone remains inert and endures indefinitely while its vessel remains undisturbed.\n\nIf the original creature dies after the clone finishes forming, the creature's soul transfers to the clone if the soul is free and willing to return. The clone is physically identical to the original and has the same personality, memories, and abilities, but none of the original's equipment. The creature's original remains, if any, become inert and can't be revived, since the creature's soul is elsewhere.", classes: ["wizard"] },
  { id: "8-control-weather", name: "Control Weather", level: 8, school: "Transmutation", castingTime: "10 minutes", range: "Self", components: "V, S, M (burning incense)", duration: "Concentration, up to 8 hours", description: "You take control of the weather within 5 miles of you for the duration. You must be outdoors to cast this spell, and it ends early if you go indoors.\n\nWhen you cast the spell, you change the current weather conditions, which are determined by the GM. You can change precipitation, temperature, and wind. It takes 1d4 × 10 minutes for the new\n\nconditions to take effect. Once they do so, you can change the conditions again. When the spell ends, the weather gradually returns to normal.\n\nWhen you change the weather conditions, find a current condition on the following tables and change its stage by one, up or down. When changing the wind, you can change its direction.\n\n**Precipitation**\n\n<table>\n  <thead>\n    <tr>\n      <th>Stage</th>\n      <th>Condition</th>\n    </tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td>1</td>\n      <td>Clear</td>\n    </tr>\n    <tr>\n      <td>2</td>\n      <td>Light clouds</td>\n    </tr>\n    <tr>\n      <td>3</td>\n      <td>Overcast or ground fog</td>\n    </tr>\n    <tr>\n      <td>4</td>\n      <td>Rain, hail, or snow</td>\n    </tr>\n    <tr>\n      <td>5</td>\n      <td>Torrential rain, driving hail, or blizzard</td>\n    </tr>\n  </tbody>\n</table>\n\n**Temperature**\n\n<table>\n  <thead>\n    <tr>\n      <th>Stage</th>\n      <th>Condition</th>\n    </tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td>1</td>\n      <td>Heat wave</td>\n    </tr>\n    <tr>\n      <td>2</td>\n      <td>Hot</td>\n    </tr>\n    <tr>\n      <td>3</td>\n      <td>Warm</td>\n    </tr>\n    <tr>\n      <td>4</td>\n      <td>Cool</td>\n    </tr>\n    <tr>\n      <td>5</td>\n      <td>Cold</td>\n    </tr>\n    <tr>\n      <td>6</td>\n      <td>Freezing</td>\n    </tr>\n  </tbody>\n</table>\n\n**Wind**\n\n<table>\n  <thead>\n    <tr>\n      <th>Stage</th>\n      <th>Condition</th>\n    </tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td>1</td>\n      <td>Calm</td>\n    </tr>\n    <tr>\n      <td>2</td>\n      <td>Moderate wind</td>\n    </tr>\n    <tr>\n      <td>3</td>\n      <td>Strong wind</td>\n    </tr>\n    <tr>\n      <td>4</td>\n      <td>Gale</td>\n    </tr>\n    <tr>\n      <td>5</td>\n      <td>Storm</td>\n    </tr>\n  </tbody>\n</table>", classes: ["cleric", "druid", "wizard"] },
  { id: "8-demiplane", name: "Demiplane", level: 8, school: "Conjuration", castingTime: "Action", range: "60 feet", components: "S", duration: "1 hour", description: "You create a shadowy Medium door on a flat solid surface that you can see within range. This door can be opened and closed, and it leads to a demiplane that is an empty room 30 feet in each dimension, made of wood or stone (your choice).\n\nWhen the spell ends, the door vanishes, and any objects inside the demiplane remain there. Any creatures inside also remain unless they opt to be shunted through the door as it vanishes, landing with the Prone condition in the unoccupied spaces closest to the door's former space.\n\nEach time you cast this spell, you can create a new demiplane or connect the shadowy door to a demiplane you created with a previous casting of this spell. Additionally, if you know the nature and contents of a demiplane created by a casting of this spell by another creature, you can connect the shadowy door to that demiplane instead.", classes: ["sorcerer", "warlock", "wizard"] },
  { id: "8-dominate-monster", name: "Dominate Monster", level: 8, school: "Enchantment", castingTime: "Action", range: "60 feet", components: "V, S", duration: "Concentration, up to 1 hour", description: "One creature you can see within range must succeed on a Wisdom saving throw or have the Charmed condition for the duration. The target has Advantage on the save if you or your allies are fighting it. Whenever the target takes damage, it repeats the save, ending the spell on itself on a success.\nYou have a telepathic link with the Charmed target while the two of you are on the same plane of existence. On your turn, you can use this link to issue commands to the target (no action required), such as \"Attack that creature,\" \"Move over there,\" or \"Fetch that object.\" The target does its best to obey on its turn. If it completes an order and doesn't receive further direction from you, it acts and moves as it likes, focusing on protecting itself.\n\nYou can command the target to take a Reaction but must take your own Reaction to do so.\n\n_Using a Higher-Level Spell Slot._ Your Concentration can last longer with a level 9 spell slot (up to 8 hours).", classes: ["bard", "sorcerer", "warlock", "wizard"] },
  { id: "8-earthquake", name: "Earthquake", level: 8, school: "Transmutation", castingTime: "Action", range: "500 feet", components: "V, S, M (a fractured rock)", duration: "Concentration, up to 1 minute", description: "Choose a point on the ground that you can see within range. For the duration, an intense tremor rips through the ground in a 100-foot-radius circle centered on that point. The ground there is Difficult Terrain.\n\nWhen you cast this spell and at the end of each of your turns for the duration, each creature on the ground in the area makes a Dexterity saving throw. On a failed save, a creature has the Prone condition, and its Concentration is broken.\n\nYou can also cause the effects below.\n\n_Fissures._ A total of 1d6 fissures open in the spell's area at the end of the turn you cast it. You choose the fissures' locations, which can't be under structures. Each fissure is 1d10 × 10 feet deep and 10 feet wide, and it extends from one edge of the spell's area to another edge. A creature in the same space as a fissure must succeed on a Dexterity saving throw or fall in. A creature that successfully saves moves with the fissure's edge as it opens.\n\n_Structures._ The tremor deals 50 Bludgeoning damage to any structure in contact with the ground in the area when you cast the spell and at the end of each of your turns until the spell ends. If a structure drops to 0 Hit Points, it collapses.\n\nA creature within a distance from a collapsing structure equal to half the structure's height makes a Dexterity saving throw. On a failed save, the creature takes 12d6 Bludgeoning damage, has the Prone condition, and is buried in the rubble, requiring a DC 20 Strength (Athletics) check as an action to escape. On a successful save, the creature takes half as much damage only.", classes: ["cleric", "druid", "sorcerer"] },
  { id: "8-glibness", name: "Glibness", level: 8, school: "Enchantment", castingTime: "Action", range: "Self", components: "V", duration: "1 hour", description: "Until the spell ends, when you make a Charisma check, you can replace the number you roll with a 15. Additionally, no matter what you say, magic that would determine if you are telling the truth indicates that you are being truthful.", classes: ["bard", "warlock"] },
  { id: "8-holy-aura", name: "Holy Aura", level: 8, school: "Abjuration", castingTime: "Action", range: "Self", components: "V, S, M (a reliquary worth 1,000+ GP)", duration: "Concentration, up to 1 minute", description: "For the duration, you emit an aura in a 30-foot Emanation. While in the aura, creatures of your choice have Advantage on all saving throws, and other creatures have Disadvantage on attack rolls against them. In addition, when a Fiend or an Undead hits an affected creature with a melee attack roll, the attacker must succeed on a Constitution saving throw or have the Blinded condition until the end of its next turn.", classes: ["cleric"] },
  { id: "8-incendiary-cloud", name: "Incendiary Cloud", level: 8, school: "Conjuration", castingTime: "Action", range: "150 feet", components: "V, S", duration: "Concentration, up to 1 minute", description: "A swirling cloud of embers and smoke fills a 20-foot-radius Sphere centered on a point within range. The cloud's area is Heavily Obscured. It lasts for the duration or until a strong wind (like that created by _Gust of Wind_) disperses it.\n\nWhen the cloud appears, each creature in it makes a Dexterity saving throw, taking 10d8 Fire damage on a failed save or half as much damage on a successful one. A creature must also make this save when the Sphere moves into its space and when it enters the Sphere or ends its turn there. A creature makes this save only once per turn.\nThe cloud moves 10 feet away from you in a direction you choose at the start of each of your turns.", classes: ["druid", "sorcerer", "wizard"] },
  { id: "8-maze", name: "Maze", level: 8, school: "Conjuration", castingTime: "Action", range: "60 feet", components: "V, S", duration: "Concentration, up to 10 minutes", description: "You banish a creature that you can see within range into a labyrinthine demiplane. The target remains there for the duration or until it escapes the maze.\n\nThe target can take a Study action to try to escape. When it does so, it makes a DC 20 Intelligence (Investigation) check. If it succeeds, it escapes, and the spell ends.\n\nWhen the spell ends, the target reappears in the space it left or, if that space is occupied, in the nearest unoccupied space.", classes: ["wizard"] },
  { id: "8-mind-blank", name: "Mind Blank", level: 8, school: "Abjuration", castingTime: "Action", range: "Touch", components: "V, S", duration: "24 hours", description: "Until the spell ends, one willing creature you touch has Immunity to Psychic damage and the Charmed condition. The target is also unaffected by anything that would sense its emotions or alignment, read its thoughts, or magically detect its location, and no spell—not even _Wish_—can gather information about the target, observe it remotely, or control its mind.", classes: ["bard", "wizard"] },
  { id: "8-power-word-stun", name: "Power Word Stun", level: 8, school: "Enchantment", castingTime: "Action", range: "60 feet", components: "V", duration: "Instantaneous", description: "You overwhelm the mind of one creature you can see within range. If the target has 150 Hit Points or fewer, it has the Stunned condition. Otherwise, its Speed is 0 until the start of your next turn.\n\nThe Stunned target makes a Constitution saving throw at the end of each of its turns, ending the condition on itself on a success.", classes: ["bard", "sorcerer", "warlock", "wizard"] },
  { id: "8-sunburst", name: "Sunburst", level: 8, school: "Evocation", castingTime: "Action", range: "150 feet", components: "V, S, M (a piece of sunstone)", duration: "Instantaneous", description: "Brilliant sunlight flashes in a 60-foot-radius Sphere centered on a point you choose within range. Each creature in the Sphere makes a Constitution saving throw. On a failed save, a creature takes 12d6 Radiant damage and has the Blinded condition for 1 minute. On a successful save, it takes half as much damage only.\n\nA creature Blinded by this spell makes another Constitution saving throw at the end of each of its turns, ending the effect on itself on a success.\n\nThis spell dispels Darkness in its area that was created by any spell.", classes: ["cleric", "druid", "sorcerer", "wizard"] },
  { id: "8-tsunami", name: "Tsunami", level: 8, school: "Conjuration", castingTime: "1 minute", range: "1 mile", components: "V, S", duration: "Concentration, up to 6 rounds", description: "A wall of water springs into existence at a point you choose within range. You can make the wall up to 300 feet long, 300 feet high, and 50 feet thick. The wall lasts for the duration.\n\nWhen the wall appears, each creature in its area makes a Strength saving throw, taking 6d10 Bludgeoning damage on a failed save or half as much damage on a successful one.\n\nAt the start of each of your turns after the wall appears, the wall, along with any creatures in it, moves 50 feet away from you. Any Huge or smaller creature inside the wall or whose space the wall enters when it moves must succeed on a Strength saving throw or take 5d10 Bludgeoning damage. A creature can take this damage only once per round. At the end of the turn, the wall's height is reduced by 50 feet, and the damage the wall deals on later rounds is reduced by 1d10. When the wall reaches 0 feet in height, the spell ends.\n\nA creature caught in the wall can move by swimming. Because of the wave's force, though, the creature must succeed on a Strength (Athletics) check against your spell save DC to move at all. If it fails the check, it can't move. A creature that moves out of the wall falls to the ground.", classes: ["druid"] },

  // -- 9th Level Spells (16 spells)

  { id: "9-astral-projection", name: "Astral Projection", level: 9, school: "Necromancy", castingTime: "1 hour", range: "10 feet", components: "V, S, M (for each of the spell's targets, one jacinth worth 1,000+ GP and one silver bar worth 100+ GP, all of which the spell consumes)", duration: "Until dispelled", description: "You and up to eight willing creatures within range project your astral bodies into the Astral Plane (the spell ends instantly if you are already on that plane). Each target's body is left behind in a state of suspended animation; it has the Unconscious condition, doesn't need food or air, and doesn't age.\n\nA target's astral form resembles its body in almost every way, replicating its game statistics and possessions. The principal difference is the addition of a silvery cord that trails from between the shoulder blades of the astral form. The cord fades from view after 1 foot. If the cord is cut—which happens only when an effect states that it does so—the target's body and astral form both die.\n\nA target's astral form can travel through the Astral Plane. The moment an astral form leaves that plane, the target's body and possessions travel along the silver cord, causing the target to re-enter its body on the new plane.\n\nAny damage or other effects that apply to an astral form have no effect on the target's body and vice versa. If a target's body or astral form drops to 0 Hit Points, the spell ends for that target. The spell ends for all the targets if you take a Magic action to dismiss it.\n\nWhen the spell ends for a target who isn't dead, the target reappears in its body and exits the state of suspended animation.", classes: ["cleric", "warlock", "wizard"] },
  { id: "9-foresight", name: "Foresight", level: 9, school: "Divination", castingTime: "1 minute", range: "Touch", components: "V, S, M (a hummingbird feather)", duration: "8 hours", description: "You touch a willing creature and bestow a limited ability to see into the immediate future. For the duration, the target has Advantage on D20 Tests, and other creatures have Disadvantage on attack rolls against it. The spell ends early if you cast it again.", classes: ["bard", "druid", "warlock", "wizard"] },
  { id: "9-gate", name: "Gate", level: 9, school: "Conjuration", castingTime: "Action", range: "60 feet", components: "V, S, M (a diamond worth 5,000+ GP)", duration: "Concentration, up to 1 minute", description: "You conjure a portal linking an unoccupied space you can see within range to a precise location on a different plane of existence. The portal is a circular opening, which you can make 5 to 20 feet in diameter. You can orient the portal in any direction you choose. The portal lasts for the duration, and the portal's destination is visible through it.\n\nThe portal has a front and a back on each plane where it appears. Travel through the portal is possible only by moving through its front. Anything that does so is instantly transported to the other plane, appearing in the unoccupied space nearest to the portal.\n\nDeities and other planar rulers can prevent portals created by this spell from opening in their presence or anywhere within their domains.\n\nWhen you cast this spell, you can speak the name of a specific creature (a pseudonym, title, or nickname doesn't work). If that creature is on a plane other than the one you are on, the portal opens next to the named creature and transports it to the nearest unoccupied space on your side of the portal. You gain no special power over the creature, and it is free to act as the GM deems appropriate. It might leave, attack you, or help you.", classes: ["cleric", "sorcerer", "warlock", "wizard"] },
  { id: "9-imprisonment", name: "Imprisonment", level: 9, school: "Abjuration", castingTime: "1 minute", range: "30 feet", components: "V, S, M (a statuette of the target worth 5,000+ GP)", duration: "Until dispelled", description: "You create a magical restraint to hold a creature that you can see within range. The target must make a Wisdom saving throw. On a successful save, the target is unaffected, and it is immune to this spell for the next 24 hours. On a failed save, the target is imprisoned. While imprisoned, the target doesn't need to breathe, eat, or drink, and it doesn't age. Divination spells can't locate or perceive the imprisoned target, and the target can't teleport.\n\nUntil the spell ends, the target is also affected by one of the following effects of your choice:\n\n**Burial.** The target is entombed beneath the earth in a hollow globe of magical force that is just large enough to contain the target. Nothing can pass into or out of the globe.\n\n**Chaining.** Chains firmly rooted in the ground hold the target in place. The target has the Restrained condition and can't be moved by any means.\n\n**Hedged Prison.** The target is trapped in a demiplane that is warded against teleportation and planar travel. The demiplane is your choice of a labyrinth, a cage, a tower, or the like.\n\n**Minimus Containment.** The target becomes 1 inch tall and is trapped inside an indestructible gemstone or a similar object. Light can pass through the gemstone (allowing the target to see out and other creatures to see in), but nothing else can pass through by any means.\n\n**Slumber.** The target has the Unconscious condition and can't be awoken.\n\n_Ending the Spell._ When you cast the spell, specify a trigger that will end it. The trigger can be as simple or as elaborate as you choose, but the GM must agree that it has a high likelihood of happening within the next decade. The trigger must be an observable action, such as someone making a particular offering at the temple of your god, saving your true love, or defeating a specific monster.\n\nA _Dispel Magic_ spell can end the spell only if it is cast with a level 9 spell slot, targeting either the prison or the component used to create it.", classes: ["warlock", "wizard"] },
  { id: "9-mass-heal", name: "Mass Heal", level: 9, school: "Abjuration", castingTime: "Action", range: "60 feet", components: "V, S", duration: "Instantaneous", description: "A flood of healing energy flows from you into creatures around you. You restore up to 700 Hit Points, divided as you choose among any number of creatures that you can see within range. Creatures healed by this spell also have the Blinded, Deafened, and Poisoned conditions removed from them.", classes: ["cleric"] },
  { id: "9-meteor-swarm", name: "Meteor Swarm", level: 9, school: "Evocation", castingTime: "Action", range: "1 mile", components: "V, S", duration: "Instantaneous", description: "Blazing orbs of fire plummet to the ground at four different points you can see within range. Each creature in a 40-foot-radius Sphere centered on each of those points makes a Dexterity saving throw. A creature takes 20d6 Fire damage and 20d6 Bludgeoning damage on a failed save or half as much damage on a successful one. A creature in the area of more than one fiery Sphere is affected only once.\n\nA nonmagical object that isn't being worn or carried also takes the damage if it's in the spell's area, and the object starts burning if it's flammable.", classes: ["sorcerer", "wizard"] },
  { id: "9-power-word-heal", name: "Power Word Heal", level: 9, school: "Enchantment", castingTime: "Action", range: "60 feet", components: "V", duration: "Instantaneous", description: "A wave of healing energy washes over one creature you can see within range. The target regains all its Hit Points. If the creature has the Charmed, Frightened, Paralyzed, Poisoned, or Stunned condition, the condition ends. If the creature has the Prone condition, it can use its Reaction to stand up.", classes: ["bard", "cleric"] },
  { id: "9-power-word-kill", name: "Power Word Kill", level: 9, school: "Enchantment", castingTime: "Action", range: "60 feet", components: "V", duration: "Instantaneous", description: "You compel one creature you can see within range to die. If the target has 100 Hit Points or fewer, it dies. Otherwise, it takes 12d12 Psychic damage.", classes: ["bard", "sorcerer", "warlock", "wizard"] },
  { id: "9-prismatic-wall", name: "Prismatic Wall", level: 9, school: "Abjuration", castingTime: "Action", range: "60 feet", components: "V, S", duration: "10 minutes", description: "A shimmering, multicolored plane of light forms a vertical opaque wall—up to 90 feet long, 30 feet high, and 1 inch thick—centered on a point within range. Alternatively, you shape the wall into a globe up to 30 feet in diameter centered on a point within range. The wall lasts for the duration. If you position the wall in a space occupied by a creature, the spell ends instantly without effect.\n\nThe wall sheds Bright Light within 100 feet and Dim Light for an additional 100 feet. You and creatures you designate when you cast the spell can pass through and be near the wall without harm. If another creature that can see the wall moves within 20 feet of it or starts its turn there, the creature must succeed on a Constitution saving throw or have the Blinded condition for 1 minute.\n\nThe wall consists of seven layers, each with a different color. When a creature reaches into or passes through the wall, it does so one layer at a time through all the layers. Each layer forces the creature to make a Dexterity saving throw or be affected by that layer's properties as described in the Prismatic Layers table.\n\nThe wall, which has AC 10, can be destroyed one layer at a time, in order from red to violet, by means specific to each layer. If a layer is destroyed, it is gone for the duration. _Antimagic Field_ has no effect on the wall, and _Dispel Magic_ can affect only the violet layer.\n\n**Prismatic Layers**\n\n<table>\n  <thead>\n    <tr>\n      <th>Order</th>\n      <th>Effects</th>\n    </tr>\n  </thead>\n  <tbody>\n    <tr>\n      <td>1</td>\n      <td>**Red.** *Failed Save:* 12d6 Fire damage. *Successful Save:* Half as much damage. *Additional Effects:* Nonmagical ranged attacks can't pass through this layer, which is destroyed if it takes at least 25 Cold damage.</td>\n    </tr>\n    <tr>\n      <td>2</td>\n      <td>**Orange.** *Failed Save:* 12d6 Acid damage. *Successful Save:* Half as much damage. *Additional Effects:* Magical ranged attacks can't pass through this layer, which is destroyed by a strong wind (such as the one created by *Gust of Wind*).</td>\n    </tr>\n    <tr>\n      <td>3</td>\n      <td>**Yellow.** *Failed Save:* 12d6 Lightning damage. *Successful Save:* Half as much damage. *Additional Effects:* The layer is destroyed if it takes at least 60 Force damage.</td>\n    </tr>\n    <tr>\n      <td>4</td>\n      <td>**Green.** *Failed Save:* 12d6 Poison damage. *Successful Save:* Half as much damage. *Additional Effects:* A *Passwall* spell, or another spell of equal or greater level that can open a portal on a solid surface, destroys this layer.</td>\n    </tr>\n    <tr>\n      <td>5</td>\n      <td>**Blue.** *Failed Save:* 12d6 Cold damage. *Successful Save:* Half as much damage. *Additional Effects:* The layer is destroyed if it takes at least 25 Fire damage.</td>\n    </tr>\n    <tr>\n      <td>6</td>\n      <td>**Indigo.** *Failed Save:* The target has the Restrained condition and makes a Constitution saving throw at the end of each of its turns. If it successfully saves three times, the condition ends. If it fails three times, it has the Petrified condition until it is freed by an effect like the *Greater Restoration* spell. The successes and failures needn't be consecutive; keep track of both until the target collects three of a kind. *Additional Effects:* Spells can't be cast through this layer, which is destroyed by Bright Light shed by the *Daylight* spell.</td>\n    </tr>\n    <tr>\n      <td>7</td>\n      <td>**Violet.** *Failed Save:* The target has the Blinded condition and makes a Wisdom saving throw at the start of your next turn. On a successful save, the condition ends. On a failed save, the condition ends, and the creature teleports to another plane of existence (GM's choice). *Additional Effects:* This layer is destroyed by *Dispel Magic*.</td>\n    </tr>\n  </tbody>\n</table>", classes: ["bard", "wizard"] },
  { id: "9-shapechange", name: "Shapechange", level: 9, school: "Transmutation", castingTime: "Action", range: "Self", components: "V, S, M (a jade circlet worth 1,500+ GP)", duration: "Concentration, up to 1 hour", description: "You shape-shift into another creature for the duration or until you take a Magic action to shape-shift into a different eligible form. The new form must be of a creature that has a Challenge Rating no higher than your level or Challenge Rating. You must have seen the sort of creature before, and it can't be a Construct or an Undead.\n\nWhen you cast the spell, you gain a number of Temporary Hit Points equal to the Hit Points of the first form into which you shape-shift. These Temporary Hit Points vanish if any remain when the spell ends.\n\nYour game statistics are replaced by the stat block of the chosen form, but you retain your creature type; alignment; personality; Intelligence, Wisdom, and Charisma scores; Hit Points; Hit Point Dice; proficiencies; and ability to communicate. If you have the Spellcasting feature, you retain it too.\n\nUpon shape-shifting, you determine whether your equipment drops to the ground or changes in size and shape to fit the new form while you're in it.", classes: ["druid", "wizard"] },
  { id: "9-storm-of-vengeance", name: "Storm of Vengeance", level: 9, school: "Conjuration", castingTime: "Action", range: "1 mile", components: "V, S", duration: "Concentration, up to 1 minute", description: "A churning storm cloud forms for the duration, centered on a point within range and spreading to a radius of 300 feet. Each creature under the cloud when it appears must succeed on a Constitution saving throw or take 2d6 Thunder damage and have the Deafened condition for the duration.\n\nAt the start of each of your later turns, the storm produces different effects, as detailed below.\n\n_Turn 2._ Acidic rain falls. Each creature and object under the cloud takes 4d6 Acid damage.\n\n_Turn 3._ You call six bolts of lightning from the cloud to strike six different creatures or objects beneath it. Each target makes a Dexterity saving throw, taking 10d6 Lightning damage on a failed save or half as much damage on a successful one.\n_Turn 4._ Hailstones rain down. Each creature under the cloud takes 2d6 Bludgeoning damage.\n\n_Turns 5–10._ Gusts and freezing rain assail the area under the cloud. Each creature there takes 1d6 Cold damage. Until the spell ends, the area is Difficult Terrain and Heavily Obscured, ranged attacks with weapons are impossible there, and strong wind blows through the area.", classes: ["druid"] },
  { id: "9-time-stop", name: "Time Stop", level: 9, school: "Transmutation", castingTime: "Action", range: "Self", components: "V", duration: "Instantaneous", description: "You briefly stop the flow of time for everyone but yourself. No time passes for other creatures, while you take 1d4 + 1 turns in a row, during which you can use actions and move as normal.\n\nThis spell ends if one of the actions you use during this period, or any effects that you create during it, affects a creature other than you or an object being worn or carried by someone other than you. In addition, the spell ends if you move to a place more than 1,000 feet from the location where you cast it.", classes: ["sorcerer", "wizard"] },
  { id: "9-true-polymorph", name: "True Polymorph", level: 9, school: "Transmutation", castingTime: "Action", range: "30 feet", components: "V, S, M (a drop of mercury, a dollop of gum arabic, and a wisp of smoke)", duration: "Concentration, up to 1 hour", description: "Choose one creature or nonmagical object that you can see within range. The creature shape-shifts into a different creature or a nonmagical object, or the object shape-shifts into a creature (the object must be neither worn nor carried). The transformation lasts for the duration or until the target dies or is destroyed, but if you maintain Concentration on this spell for the full duration, the spell lasts until dispelled.\n\nAn unwilling creature can make a Wisdom saving throw, and if it succeeds, it isn't affected by this spell.\n\n_Creature into Creature._ If you turn a creature into another kind of creature, the new form can be any kind you choose that has a Challenge Rating equal to or less than the target's Challenge Rating or level. The target's game statistics are replaced by the stat block of the new form, but it retains its Hit Points, Hit Point Dice, alignment, and personality.\n\nThe target gains a number of Temporary Hit Points equal to the Hit Points of the new form. These Temporary Hit Points vanish if any remain when the spell ends.\n\nThe target is limited in the actions it can perform by the anatomy of its new form, and it can't speak or cast spells.\n\nThe target's gear melds into the new form. The creature can't use or otherwise benefit from any of that equipment.\n\n_Object into Creature._ You can turn an object into any kind of creature, as long as the creature's size is no larger than the object's size and the creature has a Challenge Rating of 9 or lower. The creature is Friendly to you and your allies. In combat, it takes its turns immediately after yours, and it obeys your commands.\n\nIf the spell lasts more than an hour, you no longer control the creature. It might remain Friendly to you, depending on how you have treated it.\n\n_Creature into Object._ If you turn a creature into an object, it transforms along with whatever it is wearing and carrying into that form, as long as the object's size is no larger than the creature's size. The creature's statistics become those of the object, and the creature has no memory of time spent in this form after the spell ends and it returns to normal.", classes: ["bard", "warlock", "wizard"] },
  { id: "9-true-resurrection", name: "True Resurrection", level: 9, school: "Necromancy", castingTime: "1 hour", range: "Touch", components: "V, S, M (diamonds worth 25,000+ GP, which the spell consumes)", duration: "Instantaneous", description: "You touch a creature that has been dead for no longer than 200 years and that died for any reason except old age. The creature is revived with all its Hit Points.\n\nThis spell closes all wounds, neutralizes any poison, cures all magical contagions, and lifts any curses affecting the creature when it died. The spell replaces damaged or missing organs and limbs. If the creature was Undead, it is restored to its non-Undead form.\n\nThe spell can provide a new body if the original no longer exists, in which case you must speak the creature's name. The creature then appears in an unoccupied space you choose within 10 feet of you.", classes: ["cleric", "druid"] },
  { id: "9-weird", name: "Weird", level: 9, school: "Illusion", castingTime: "Action", range: "120 feet", components: "V, S", duration: "Concentration, up to 1 minute", description: "You try to create illusory terrors in others' minds. Each creature of your choice in a 30-foot-radius Sphere centered on a point within range makes a Wisdom saving throw. On a failed save, a target takes 10d10 Psychic damage and has the Frightened condition for the duration. On a successful save, a target takes half as much damage only.\n\nA Frightened target makes a Wisdom saving throw at the end of each of its turns. On a failed save, it takes 5d10 Psychic damage. On a successful save, the spell ends on that target.", classes: ["warlock", "wizard"] },
  { id: "9-wish", name: "Wish", level: 9, school: "Conjuration", castingTime: "Action", range: "Self", components: "V", duration: "Instantaneous", description: "_Wish_ is the mightiest spell a mortal can cast. By simply speaking aloud, you can alter reality itself.\n\nThe basic use of this spell is to duplicate any other spell of level 8 or lower. If you use it this way, you don't need to meet any requirements to cast that spell, including costly components. The spell simply takes effect.\n\nAlternatively, you can create one of the following effects of your choice:\n\n**Object Creation.** You create one object of up to 25,000 GP in value that isn't a magic item. The object can be no more than 300 feet in any dimension, and it appears in an unoccupied space that you can see on the ground.\n\n**Instant Health.** You allow yourself and up to twenty creatures that you can see to regain all Hit Points, and you end all effects on them listed in the _Greater Restoration_ spell.\n\n**Resistance.** You grant up to ten creatures that you can see Resistance to one damage type that you choose. This Resistance is permanent.\n\n**Spell Immunity.** You grant up to ten creatures you can see immunity to a single spell or other magical effect for 8 hours.\n\n**Sudden Learning.** You replace one of your feats with another feat for which you are eligible. You lose all the benefits of the old feat and gain the benefits of the new one. You can't replace a feat that is a prerequisite for any of your other feats or features.\n\n**Roll Redo.** You undo a single recent event by forcing a reroll of any die roll made within the last round (including your last turn). Reality reshapes itself to accommodate the new result. For example, a _Wish_ spell could undo an ally's failed saving throw or a foe's Critical Hit. You can force the reroll to be made with Advantage or Disadvantage, and you choose whether to use the reroll or the original roll.\n\n**Reshape Reality.** You may wish for something not included in any of the other effects. To do so, state your wish to the GM as precisely as possible. The GM has great latitude in ruling what occurs in such an instance; the greater the wish, the greater the likelihood that something goes wrong. This spell might simply fail, the effect you desire might be achieved only in part, or you might suffer an unforeseen consequence as a result of how you worded the wish. For example, wishing that a villain were dead might propel you forward in time to a period when that villain is no longer alive, effectively removing you from the game.\n\nSimilarly, wishing for a Legendary magic item or an Artifact might instantly transport you to the presence of the item's current owner. If your wish is granted and its effects have consequences for a whole community, region, or world, you are likely to attract powerful foes. If your wish would affect a god, the god's divine servants might instantly intervene to prevent it or to encourage you to craft the wish in a particular way. If your wish would undo the multiverse itself, your wish fails.\n\nThe stress of casting _Wish_ to produce any effect other than duplicating another spell weakens you. After enduring that stress, each time you cast a spell until you finish a Long Rest, you take 1d10 Necrotic damage per level of that spell. This damage can't be reduced or prevented in any way. In addition, your Strength score becomes 3 for 2d4 days. For each of those days that you spend resting and doing nothing more than light activity, your remaining recovery time decreases by 2 days. Finally, there is a 33 percent chance that you are unable to cast _Wish_ ever again if you suffer this stress.", classes: ["sorcerer", "wizard"] },
] as const
